# ── SSE Live Event Bus ────────────────────────────────────────────────────────
# Global set of asyncio Queues — one per connected /api/live-events client
_sse_clients: set[asyncio.Queue] = set()
_active_calls: int = 0


async def emit_live_event(event_type: str, data: dict):
    """Push a live event to all connected SSE clients."""
    payload = json.dumps({"type": event_type, "timestamp": datetime.utcnow().isoformat(), **data})
    dead = set()
    for q in _sse_clients:
        try:
            q.put_nowait(payload)
        except asyncio.QueueFull:
            dead.add(q)
    _sse_clients.difference_update(dead)

