twilio_client = TwilioClient(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN) if TWILIO_ACCOUNT_SID else None


# ── SMS Confirmation ──────────────────────────────────────────────────────────

async def send_sms_confirmation(to_phone: str, details: dict, config: dict):
    """Send post-booking SMS with appointment details + address. Respects opt-out list."""
    if not twilio_client or not TWILIO_FROM_NUMBER:
        log.warning("SMS not configured — skipping confirmation")
        return

    # Check opt-out list
    phone_digits = "".join(c for c in to_phone if c.isdigit())
    try:
        with open("optouts.json") as f:
            optouts = json.load(f)
        if any(o.get("phone") == phone_digits for o in optouts):
            log.info(f"SMS suppressed — {phone_digits} is opted out")
            return
    except (FileNotFoundError, json.JSONDecodeError):
        pass

    cfg = config or BUSINESS
    dt_str = details.get("formatted_datetime", f"{details['date']} at {details['time']}")
    staff_line = f"\nBarber/Stylist: {details['staff']}" if details.get("staff") else ""
    address = cfg.get("address", "")

    body = (
        f"Confirmed! {details['name']}, your {details['service']} at {cfg['name']} "
        f"is booked for {dt_str}.{staff_line}\n"
        f"📍 {address}\n"
        f"Questions? Call {cfg.get('phone', '')}."
    )

    to = "+1" + "".join(c for c in to_phone if c.isdigit()) if not to_phone.startswith("+") else to_phone

    try:
        twilio_client.messages.create(body=body, from_=TWILIO_FROM_NUMBER, to=to)
        log.info(f"SMS sent to {to}")
        if details.get("appointment_id"):
            mark_sms_sent(details["appointment_id"])
    except Exception as e:
        log.error(f"SMS send failed: {e}")


# ── Deepgram TTS ─────────────────────────────────────────────────────────────

async def text_to_speech_mulaw(text: str, voice_id: str = None) -> bytes:
    voice = voice_id or BUSINESS.get("ai_voice_id", "aura-asteria-en")
    url = (
        f"https://api.deepgram.com/v1/speak"
        f"?model={voice}&encoding=mulaw&sample_rate=8000&container=none"
    )
    async with httpx.AsyncClient(timeout=20) as client:
        r = await client.post(
            url,
            headers={"Authorization": f"Token {DEEPGRAM_API_KEY}", "Content-Type": "application/json"},
            json={"text": text},
        )
        r.raise_for_status()
        return r.content


def chunk_audio(audio_bytes: bytes, chunk_size: int = 32000) -> list[bytes]:
    return [audio_bytes[i:i + chunk_size] for i in range(0, len(audio_bytes), chunk_size)]


# ── Twilio Webhooks ───────────────────────────────────────────────────────────

async def verify_twilio_signature(request: Request) -> bool:
    """Validate Twilio's X-Twilio-Signature HMAC. Returns True if valid (or unconfigured)."""
    if not TWILIO_AUTH_TOKEN:
        log.warning("TWILIO_AUTH_TOKEN not set — skipping webhook signature check (dev mode)")
        return True
    sig = request.headers.get("X-Twilio-Signature", "")
    url = str(request.url)
    try:
        body = await request.body()
        # Parse form params for HMAC computation
        from urllib.parse import parse_qs
        params: dict = {}
        for k, v in parse_qs(body.decode()).items():
            params[k] = v[0] if len(v) == 1 else v
        validator = RequestValidator(TWILIO_AUTH_TOKEN)
        return validator.validate(url, params, sig)
    except Exception as e:
        log.error(f"Twilio signature check error: {e}")
        return False


@app.post("/incoming-call")
async def incoming_call(request: Request):
    if not await verify_twilio_signature(request):
        log.warning("Twilio signature verification FAILED — rejecting /incoming-call")
        return Response(content="Forbidden", status_code=403)

    host = request.headers.get("host", "")
    ws_url = f"wss://{host}/media-stream"
    log.info(f"Incoming call → {ws_url}")

    response = VoiceResponse()
    connect = Connect()
    connect.stream(url=ws_url)
    response.append(connect)
    return Response(content=str(response), media_type="application/xml")


@app.post("/transfer")
async def transfer_call(request: Request):
    """TwiML endpoint to forward call to owner's phone."""
    form = await request.form()
    to = form.get("to") or BUSINESS.get("owner_phone", "")
    response = VoiceResponse()
    if to:
        response.say("Please hold while I connect you.")
        dial = Dial()
        dial.number(to)
        response.append(dial)
    else:
        response.say("I'm sorry, no one is available right now. Please call back or leave a message.")
    return Response(content=str(response), media_type="application/xml")


