@app.post("/api/send-reminder")
async def api_send_reminder(request: Request):
    """Send a 24h-before appointment reminder SMS."""
    if not twilio_client:
        return JSONResponse({"ok": False, "error": "Twilio not configured"})
    data = await request.json()
    appt_id = data.get("appointment_id")
    if not appt_id:
        return JSONResponse({"ok": False, "error": "appointment_id required"}, status_code=400)

    with get_db() as db:
        appt = db.execute("SELECT * FROM appointments WHERE id = ?", (appt_id,)).fetchone()

    if not appt:
        return JSONResponse({"ok": False, "error": "Not found"}, status_code=404)

    dt = datetime.strptime(f"{appt['date']} {appt['time']}", "%Y-%m-%d %H:%M")
    formatted = dt.strftime("%A, %B %d at %-I:%M %p")
    to = "+1" + appt["phone"] if not appt["phone"].startswith("+") else appt["phone"]

    body = (
        f"Reminder: {appt['name']}, your {appt['service']} at {BUSINESS['name']} "
        f"is tomorrow — {formatted}. "
        f"📍 {BUSINESS.get('address', '')} "
        f"Reply CANCEL to cancel."
    )

    try:
        twilio_client.messages.create(body=body, from_=TWILIO_FROM_NUMBER, to=to)
        return JSONResponse({"ok": True, "sent_to": to})
    except Exception as e:
        return JSONResponse({"ok": False, "error": str(e)}, status_code=500)


