@app.get("/api/analytics")
async def api_analytics():
    """Return analytics data from the SQLite DB."""
    from datetime import timedelta
    today = date.today()
    stats = get_dashboard_stats()

    with get_db() as db:
        # Bookings by day — last 14 days
        bookings_by_day = []
        for i in range(13, -1, -1):
            d = (today - timedelta(days=i)).isoformat()
            count = db.execute(
                "SELECT COUNT(*) FROM appointments WHERE date = ? AND status = 'confirmed'", (d,)
            ).fetchone()[0]
            bookings_by_day.append({"date": d, "count": count})

        # Peak hours (hour of day when bookings happen)
        peak_raw = db.execute(
            "SELECT CAST(strftime('%H', time) AS INTEGER) as hour, COUNT(*) as count "
            "FROM appointments WHERE status = 'confirmed' GROUP BY hour ORDER BY hour"
        ).fetchall()
        peak_hours = [{"hour": r["hour"], "count": r["count"]} for r in peak_raw]

        # Service breakdown
        svc_raw = db.execute(
            "SELECT service, COUNT(*) as count FROM appointments "
            "WHERE status = 'confirmed' GROUP BY service ORDER BY count DESC LIMIT 8"
        ).fetchall()
        service_breakdown = [{"service": r["service"], "count": r["count"]} for r in svc_raw]

        # Total missed
        total_missed = db.execute("SELECT COUNT(*) FROM missed_calls").fetchone()[0]

    return JSONResponse({
        "total_booked": stats["total_booked"],
        "week_booked": stats["week"],
        "today_booked": stats["today"],
        "missed_today": stats["missed_today"],
        "total_missed": total_missed,
        "bookings_by_day": bookings_by_day,
        "peak_hours": peak_hours,
        "service_breakdown": service_breakdown,
    })


