@app.get("/outreach", response_class=HTMLResponse)
async def outreach_page():
    """Render outreach templates as a dark-themed page."""
    try:
        with open("outreach_templates.md", "r") as f:
            content = f.read()
    except FileNotFoundError:
        content = "Outreach templates not found."

    import re
    html = content
    html = re.sub(r'^### (.+)$', r'<h3>\1</h3>', html, flags=re.MULTILINE)
    html = re.sub(r'^## (.+)$', r'<h2>\1</h2>', html, flags=re.MULTILINE)
    html = re.sub(r'^# (.+)$', r'<h1>\1</h1>', html, flags=re.MULTILINE)
    html = re.sub(r'\*\*(.+?)\*\*', r'<strong>\1</strong>', html)
    html = re.sub(r'\*(.+?)\*', r'<em>\1</em>', html)
    # Blockquotes → styled message bubbles
    html = re.sub(r'^> (.+)$', r'<div class="msg">\1</div>', html, flags=re.MULTILINE)
    html = html.replace('\n\n', '</p><p>')

    return f"""<!DOCTYPE html>
<html><head><meta charset="utf-8"><title>RingDesk — Outreach Playbook</title>
<style>
body{{font-family:system-ui;max-width:860px;margin:0 auto;padding:2rem 1.5rem;
background:#0a0a0a;color:#e0e0e0;line-height:1.7}}
h1{{color:#fff;font-size:2rem;margin-bottom:.25rem}}
h2{{color:#a78bfa;margin-top:2.5rem;border-bottom:1px solid #222;padding-bottom:.5rem}}
h3{{color:#60a5fa;margin-top:1.5rem}}
strong{{color:#fff}}
p{{color:#aaa;margin:.75rem 0}}
.msg{{background:#1a1a2e;border-left:3px solid #7c3aed;padding:.75rem 1rem;
margin:.5rem 0;border-radius:0 8px 8px 0;color:#c4b5fd;font-style:italic}}
hr{{border:none;border-top:1px solid #1e1e1e;margin:1.5rem 0}}
table{{width:100%;border-collapse:collapse;margin:1rem 0}}
th{{background:#1a1a1a;padding:.6rem 1rem;text-align:left;color:#888;font-size:.8rem}}
td{{padding:.6rem 1rem;border-bottom:1px solid #1a1a1a;color:#bbb}}
em{{color:#9ca3af}}
a{{color:#a78bfa}}
</style></head><body>
<a href="/" style="color:#666;text-decoration:none;font-size:.85rem">← Back to RingDesk</a>
<p>{html}</p>
</body></html>"""


