@app.post("/api/voice-preview")
async def api_voice_preview(request: Request):
    """Call Deepgram TTS and return raw audio for browser playback."""
    data = await request.json()
    text = data.get("text", "Hi! I'm your AI receptionist. How can I help you today?")
    voice_id = data.get("voice_id", "aura-asteria-en")

    if not DEEPGRAM_API_KEY:
        return JSONResponse({"error": "DEEPGRAM_API_KEY not configured"}, status_code=503)

    url = f"https://api.deepgram.com/v1/speak?model={voice_id}&encoding=linear16&sample_rate=24000&container=wav"
    async with httpx.AsyncClient(timeout=20) as client:
        r = await client.post(
            url,
            headers={"Authorization": f"Token {DEEPGRAM_API_KEY}", "Content-Type": "application/json"},
            json={"text": text},
        )
        r.raise_for_status()
        return Response(content=r.content, media_type="audio/wav")


