@app.post("/api/book-appointment")
async def book_appointment_api(request: Request):
    """Book an appointment via the API. Writes to SQLite and returns confirmation URL."""
    body = await request.json()
    name    = body.get("name", "").strip()
    phone   = body.get("phone", "").strip()
    service = body.get("service", "").strip()
    date_s  = body.get("date", "").strip()
    time_s  = body.get("time", "").strip()
    barber  = body.get("barber", "").strip() or None
    notes   = body.get("notes", "").strip() or None

    if not all([name, phone, service, date_s, time_s]):
        return JSONResponse({"error": "name, phone, service, date, time are required"}, status_code=400)

    phone_clean = "".join(c for c in phone if c.isdigit())

    # Check SMS opt-outs before booking
    try:
        with open("optouts.json") as f:
            optouts = json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        optouts = []
    sms_ok = phone_clean not in [o.get("phone","") for o in optouts]

    with get_db() as db:
        cursor = db.execute(
            """INSERT INTO appointments (name, phone, service, staff, date, time, duration, notes)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?)""",
            (name, phone_clean, service, barber, date_s, time_s, 60, notes)
        )
        appt_id = cursor.lastrowid

    import urllib.parse
    params = urllib.parse.urlencode({
        "name": name, "service": service, "date": date_s, "time": time_s,
        **({"barber": barber} if barber else {}),
    })
    confirmation_url = f"/booking-confirmed?{params}"

    # Fire-and-forget SMS if not opted out
    if sms_ok:
        asyncio.create_task(send_sms_confirmation(phone, {
            "name": name, "service": service, "date": date_s, "time": time_s,
            "staff": barber, "appointment_id": appt_id,
        }, BUSINESS))

    # Emit to live monitor
    asyncio.create_task(emit_live_event("booking_confirmed", {
        "phone": phone_clean,
        "message": f"Booked: {name} — {service} on {date_s} at {time_s}",
        "appointment_id": appt_id,
    }))
    if sms_ok:
        asyncio.create_task(emit_live_event("sms_sent", {
            "phone": phone_clean,
            "message": f"SMS confirmation queued for {name}",
        }))

    return {"ok": True, "appointment_id": appt_id, "confirmation_url": confirmation_url, "sms_queued": sms_ok}


@app.get("/api/appointments")
async def list_appointments(
    status: Optional[str] = None,
    from_date: Optional[str] = None,
    to_date: Optional[str] = None,
    limit: int = 500,
):
    """Return all appointments as JSON, with optional filters."""
    query = "SELECT * FROM appointments WHERE 1=1"
    params = []
    if status:
        query += " AND status = ?"
        params.append(status)
    if from_date:
        query += " AND date >= ?"
        params.append(from_date)
    if to_date:
        query += " AND date <= ?"
        params.append(to_date)
    query += f" ORDER BY date DESC, time DESC LIMIT {limit}"

    with get_db() as db:
        rows = db.execute(query, params).fetchall()
    return {"appointments": [dict(r) for r in rows], "total": len(rows)}


