async def waitlist_add(request: Request):
    """Add a customer to the waitlist. Persists to waitlist.json."""
    body = await request.json()
    name         = body.get("name", "").strip()
    phone        = "".join(c for c in body.get("phone", "") if c.isdigit())
    service      = body.get("service", "").strip()
    preferred_day = body.get("preferred_day", "").strip()
    if not all([name, phone, service]):
        return JSONResponse({"error": "name, phone, service required"}, status_code=400)
    try:
        with open("waitlist.json") as f:
            waitlist = json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        waitlist = []
    entry = {
        "name": name, "phone": phone, "service": service,
        "preferred_day": preferred_day,
        "added_at": datetime.utcnow().isoformat(),
    }
    waitlist.append(entry)
    with open("waitlist.json", "w") as f:
        json.dump(waitlist, f, indent=2)
    position = len([w for w in waitlist if w.get("service") == service])
    asyncio.create_task(emit_live_event("waitlist_joined", {
        "message": f"{name} joined waitlist for {service}",
        "phone": phone,
    }))
    return {"ok": True, "position": position, "service": service, "preferred_day": preferred_day}


