@app.get("/api/export/appointments.csv")
async def export_appointments_csv(
    status: Optional[str] = None,
    from_date: Optional[str] = None,
    to_date: Optional[str] = None,
):
    """Download all appointments as a CSV file."""
    query = "SELECT id, name, phone, service, staff, date, time, status, notes, sms_sent, created_at FROM appointments WHERE 1=1"
    params = []
    if status:
        query += " AND status = ?"
        params.append(status)
    if from_date:
        query += " AND date >= ?"
        params.append(from_date)
    if to_date:
        query += " AND date <= ?"
        params.append(to_date)
    query += " ORDER BY date DESC, time DESC"

    with get_db() as db:
        rows = db.execute(query, params).fetchall()

    import io
    output = io.StringIO()
    writer = csv.writer(output)
    writer.writerow(["id", "name", "phone", "service", "staff", "date", "time", "status", "notes", "sms_sent", "created_at"])
    for row in rows:
        writer.writerow(list(row))

    return Response(
        content=output.getvalue(),
        media_type="text/csv",
        headers={"Content-Disposition": "attachment; filename=appointments.csv"},
    )


@app.post("/api/sms-optout")
async def sms_optout(request: Request):
    """Add a phone number to the SMS opt-out list."""
    body = await request.json()
    phone = "".join(c for c in body.get("phone", "") if c.isdigit())
    if not phone:
        return JSONResponse({"error": "phone required"}, status_code=400)

    try:
        with open("optouts.json") as f:
            optouts = json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        optouts = []

    if not any(o.get("phone") == phone for o in optouts):
        optouts.append({"phone": phone, "opted_out_at": datetime.utcnow().isoformat()})
        with open("optouts.json", "w") as f:
            json.dump(optouts, f, indent=2)

    return {"ok": True, "phone": phone, "total_optouts": len(optouts)}


