@app.get("/health-detailed")
async def health_detailed():
    """Per-component health check: DB, Deepgram, Twilio, SMS optouts, appointments, server uptime."""
    import os as _os
    results: dict = {}
    all_ok = True

    # Database ping
    try:
        t0 = _time.time()
        with get_db() as db:
            db.execute("SELECT 1").fetchone()
        results["database"] = {"ok": True, "latency_ms": round((_time.time() - t0) * 1000, 2)}
    except Exception as e:
        results["database"] = {"ok": False, "error": str(e)}
        all_ok = False

    # Deepgram
    dg_key = bool(DEEPGRAM_API_KEY)
    results["deepgram"] = {"ok": dg_key, "configured": dg_key}
    if not dg_key:
        all_ok = False

    # Twilio
    tw_ok = bool(TWILIO_ACCOUNT_SID and TWILIO_AUTH_TOKEN)
    results["twilio"] = {"ok": tw_ok, "configured": tw_ok}
    if not tw_ok:
        all_ok = False

    # SMS optouts
    try:
        with open("optouts.json") as f:
            optout_data = json.load(f)
        results["sms_optouts"] = {"ok": True, "count": len(optout_data)}
    except (FileNotFoundError, json.JSONDecodeError):
        results["sms_optouts"] = {"ok": True, "count": 0}

    # Appointments DB row count
    try:
        with get_db() as db:
            total = db.execute("SELECT COUNT(*) FROM appointments").fetchone()[0]
        results["appointments_db"] = {"ok": True, "total": total}
    except Exception as e:
        results["appointments_db"] = {"ok": False, "error": str(e)}
        all_ok = False

    # Server uptime
    results["server"] = {
        "ok": True,
        "uptime_s": round(_time.time() - _server_start_time, 1),
        "pid": _os.getpid(),
    }

    return {"status": "healthy" if all_ok else "degraded", **results}


