@app.get("/shop/{slug}", response_class=HTMLResponse)
async def shop_profile(slug: str):
    """Dynamic public shop profile page generated from locations.json."""
    # Load locations
    try:
        with open("locations.json") as f:
            data = json.load(f)
        locations = data.get("locations", data) if isinstance(data, dict) else data
    except (FileNotFoundError, json.JSONDecodeError):
        locations = []

    # Find matching location by slug
    location = None
    for loc in locations:
        loc_slug = loc.get("name", "").lower().replace(" ", "-").replace("—", "-").replace("–", "-")
        # Normalize multiple dashes
        import re as _re
        loc_slug = _re.sub(r"-+", "-", loc_slug).strip("-")
        if loc_slug == slug:
            location = loc
            break

    if not location:
        return HTMLResponse(content=f"""<!DOCTYPE html>
<html lang="en"><head><meta charset="utf-8"><title>Not Found — RingDesk</title>
<style>*{{box-sizing:border-box;margin:0;padding:0}}body{{font-family:-apple-system,sans-serif;background:#080808;color:#e8e8e8;min-height:100vh;display:flex;align-items:center;justify-content:center;text-align:center;gap:1rem;flex-direction:column;padding:2rem}}
h1{{font-size:2rem;font-weight:900;color:#fff;margin-bottom:.5rem}}p{{color:#666;font-size:.9rem}}a{{color:#a78bfa;text-decoration:none}}</style></head>
<body><h1>Shop not found</h1><p>No shop matching "<strong>{slug}</strong>" was found.</p><a href="/">← Back to RingDesk</a></body></html>""", status_code=404)

    # Load services from shop_config.json
    services = []
    try:
        with open("shop_config.json") as f:
            cfg = json.load(f)
        services = cfg.get("services", [])
    except (FileNotFoundError, json.JSONDecodeError):
        pass

    name    = location.get("name", "Our Shop")
    address = location.get("address", "")
    phone   = location.get("phone", "")
    ai_name = location.get("ai_name", "our AI receptionist")
    status  = location.get("status", "active")
    phone_href = f"tel:+1{phone}" if phone and not phone.startswith("+") else f"tel:{phone}"

