@app.get("/api/live-events")
async def live_events(request: Request):
    """SSE endpoint — streams real-time call events to connected clients."""
    q: asyncio.Queue = asyncio.Queue(maxsize=100)
    _sse_clients.add(q)

    async def event_generator():
        global _active_calls
        try:
            # Send initial state
            init = json.dumps({"type": "init", "timestamp": datetime.utcnow().isoformat(),
                               "active_calls": _active_calls, "message": "Connected to RingDesk live monitor"})
            yield f"data: {init}\n\n"
            while True:
                try:
                    payload = await asyncio.wait_for(q.get(), timeout=15.0)
                    yield f"data: {payload}\n\n"
                except asyncio.TimeoutError:
                    # keepalive comment so proxy/browser doesn't close idle connection
                    yield ":\n\n"
                if await request.is_disconnected():
                    break
        finally:
            _sse_clients.discard(q)

    return StreamingResponse(event_generator(), media_type="text/event-stream",
                             headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"})


