@app.post("/api/partner-apply")
async def partner_apply(request: Request):
    """Save partner application to partners.json."""
    body = await request.json()
    partners_file = "partners.json"
    try:
        with open(partners_file) as f:
            data = json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        data = {"partners": []}
    entry = {
        "id": len(data["partners"]) + 1,
        "applied_at": datetime.utcnow().isoformat(),
        "status": "pending",
        **body,
    }
    data["partners"].append(entry)
    with open(partners_file, "w") as f:
        json.dump(data, f, indent=2)
    log.info(f"Partner application from {body.get('company')} saved")
    return {"ok": True, "id": entry["id"]}

@app.get("/business-plan", response_class=HTMLResponse)
async def business_plan_page():
    """Render the business plan as a simple page."""
    try:
        with open("business_plan.md", "r") as f:
            content = f.read()
    except FileNotFoundError:
        content = "Business plan not found."

    # Simple markdown-to-html (just headings + paragraphs)
    import re
    html = content
    html = re.sub(r'^### (.+)$', r'<h3>\1</h3>', html, flags=re.MULTILINE)
    html = re.sub(r'^## (.+)$', r'<h2>\1</h2>', html, flags=re.MULTILINE)
    html = re.sub(r'^# (.+)$', r'<h1>\1</h1>', html, flags=re.MULTILINE)
    html = re.sub(r'\*\*(.+?)\*\*', r'<strong>\1</strong>', html)
    html = re.sub(r'\*(.+?)\*', r'<em>\1</em>', html)
    html = html.replace('\n\n', '</p><p>')

    return f"""<!DOCTYPE html>
<html><head><meta charset="utf-8"><title>RingDesk Business Plan</title>
<style>
body{{font-family:system-ui;max-width:800px;margin:0 auto;padding:2rem 1.5rem;
background:#0a0a0a;color:#e0e0e0;line-height:1.7}}
h1{{color:#fff;font-size:2rem;margin-bottom:.25rem}}
h2{{color:#a78bfa;margin-top:2.5rem;border-bottom:1px solid #222;padding-bottom:.5rem}}
h3{{color:#fff;margin-top:1.5rem}}
strong{{color:#fff}}
table{{width:100%;border-collapse:collapse;margin:1rem 0}}
th{{background:#1a1a1a;padding:.6rem 1rem;text-align:left;color:#888;font-size:.8rem}}
td{{padding:.6rem 1rem;border-bottom:1px solid #1a1a1a}}
p{{color:#aaa;margin:.75rem 0}}
a{{color:#a78bfa}}
</style></head><body>
<a href="/" style="color:#666;text-decoration:none;font-size:.85rem">← Back to RingDesk</a>
<p><p>{html}</p></p>
</body></html>"""


# ── Media Stream WebSocket ────────────────────────────────────────────────────

class CallSession:
    def __init__(self, ws: WebSocket, config: dict):
        self.ws = ws
        self.config = config
        self.stream_sid: Optional[str] = None
        self.call_sid: Optional[str] = None
        self.caller_phone: Optional[str] = None
        self.conversation: list = []
        self.language: str = "en"
        self.is_speaking = False
        self.processing = False
        self.dg_ws = None
        self._greeted = False
        self._transfer_to: Optional[str] = None

    async def start(self):
        dg_url = (
            "wss://api.deepgram.com/v1/listen"
            "?encoding=mulaw&sample_rate=8000&channels=1"
            "&model=nova-2&language=multi"
            "&punctuate=true&endpointing=400&interim_results=true&smart_format=true"
        )
        self.dg_ws = await websockets.connect(
            dg_url,
            extra_headers={"Authorization": f"Token {DEEPGRAM_API_KEY}"},
        )
        asyncio.create_task(self._listen_deepgram())
        log.info("Deepgram STT connected (multilingual)")

    async def _listen_deepgram(self):
        try:
            async for msg in self.dg_ws:
                data = json.loads(msg)
                if data.get("type") != "Results":
                    continue
                alt = data.get("channel", {}).get("alternatives", [{}])[0]
                transcript = alt.get("transcript", "").strip()
                speech_final = data.get("speech_final", False)
                is_final = data.get("is_final", False)

                if transcript and speech_final and is_final and not self.is_speaking and not self.processing:
                    # Detect language on first real utterance
                    detected = detect_language(transcript)
                    if detected == "es":
                        self.language = "es"
                    asyncio.create_task(self._handle_utterance(transcript))
        except Exception as e:
            log.error(f"Deepgram listener: {e}")

    async def _handle_utterance(self, text: str):
        self.processing = True
        try:
            log.info(f"[{self.language}] Caller: {text!r}")
            self.conversation.append({"role": "user", "content": text})

            response_text, updated_history, metadata = get_agent_response(
                self.conversation,
                config=self.config,
                call_sid=self.call_sid or "",
                language=self.language,
            )
            self.conversation = updated_history

            # Handle post-booking SMS
            if metadata.get("sms_details"):
                details = metadata["sms_details"]
                phone = details.get("phone") or self.caller_phone or ""
                asyncio.create_task(send_sms_confirmation(phone, details, self.config))

            # Handle live transfer request
            if metadata.get("transfer_to"):
                self._transfer_to = metadata["transfer_to"]

            log.info(f"Agent: {response_text!r}")
            if response_text:
                await self._speak(response_text)

            # After speaking the transfer message, end stream so Twilio can forward
            if self._transfer_to:
                await asyncio.sleep(1)
                log.info(f"Initiating transfer to {self._transfer_to}")

        except Exception as e:
            log.error(f"Agent error: {e}")
            msg = "Lo siento, hubo un problema." if self.language == "es" else "I'm sorry, something went wrong. Someone will call you back shortly."
            await self._speak(msg)
        finally:
            self.processing = False

    async def _speak(self, text: str):
        if not self.stream_sid:
            return
        self.is_speaking = True
        try:
            voice_id = self.config.get("ai_voice_id", "aura-asteria-en")
            audio = await text_to_speech_mulaw(text, voice_id)
            for chunk in chunk_audio(audio):
                await self.ws.send_json({
                    "event": "media",
                    "streamSid": self.stream_sid,
                    "media": {"payload": base64.b64encode(chunk).decode()},
                })
                await asyncio.sleep(0.01)
            await self.ws.send_json({
                "event": "mark",
                "streamSid": self.stream_sid,
                "mark": {"name": "done"},
            })
        except Exception as e:
            log.error(f"TTS error: {e}")
        finally:
            self.is_speaking = False

    async def send_audio_to_deepgram(self, payload_b64: str):
        if self.dg_ws and not self.is_speaking:
            try:
                await self.dg_ws.send(base64.b64decode(payload_b64))
            except Exception as e:
                log.error(f"Deepgram send: {e}")

    async def greet(self):
        if self._greeted:
            return
        self._greeted = True
        global _active_calls
        _active_calls += 1
        asyncio.create_task(emit_live_event("call_started", {
            "phone": self.caller_phone or "unknown",
            "message": f"Incoming call — AI receptionist answered",
        }))
        tmpl = self.config.get(
            "greeting",
            "Thank you for calling {business_name}! How can I help you today?"
        )
        greeting = tmpl.format(business_name=self.config.get("name", "us"))
        await self._speak(greeting)

    async def close(self):
        global _active_calls
        _active_calls = max(0, _active_calls - 1)
        asyncio.create_task(emit_live_event("call_ended", {
            "phone": self.caller_phone or "unknown",
            "message": "Call ended",
            "active_calls": _active_calls,
        }))
        if self.dg_ws:
            try:
                await self.dg_ws.close()
            except Exception:
                pass


@app.websocket("/media-stream")
async def media_stream(websocket: WebSocket):
    await websocket.accept()
    session = CallSession(websocket, BUSINESS)
    await session.start()

    try:
        async for raw in websocket.iter_text():
            msg = json.loads(raw)
            event = msg.get("event")

            if event == "start":
                sd = msg.get("start", {})
                session.stream_sid = sd.get("streamSid")
                session.call_sid   = sd.get("callSid")
                # Twilio passes caller number in customParameters if configured
                session.caller_phone = sd.get("customParameters", {}).get("caller_phone", "")
                log.info(f"Stream started sid={session.stream_sid} call={session.call_sid}")
                asyncio.create_task(session.greet())

            elif event == "media":
                await session.send_audio_to_deepgram(msg["media"]["payload"])

            elif event == "stop":
                log.info("Stream stopped")
                # Log as missed if no conversation happened
                if not session.conversation and session.call_sid:
                    log_missed_call(
                        phone=session.caller_phone or "",
                        call_sid=session.call_sid,
                        reason="hung_up_early",
                    )
                break

    except WebSocketDisconnect:
        log.info("WebSocket disconnected")
    except Exception as e:
        log.error(f"WebSocket error: {e}")
    finally:
        await session.close()


# ── Reminder Background Job ───────────────────────────────────────────────────

async def send_reminder_sms(appt: dict, hours_ahead: int):
    """Send a reminder SMS for an appointment."""
    if not twilio_client or not TWILIO_FROM_NUMBER:
        return

    from appointments import mark_reminder_sent
    dt = datetime.strptime(f"{appt['date']} {appt['time']}", "%Y-%m-%d %H:%M")
    formatted = dt.strftime("%A, %B %d at %-I:%M %p")
    staff_note = f" with {appt['staff']}" if appt.get("staff") else ""
    label = "tomorrow" if hours_ahead == 24 else "in 2 hours"

    body = (
        f"Reminder: {appt['name']}, your {appt['service']}{staff_note} "
        f"at {BUSINESS['name']} is {label} — {formatted}.\n"
        f"📍 {BUSINESS.get('address', '')}\n"
        f"Reply CANCEL to cancel. See you soon!"
    )

    phone = appt["phone"]
    to = f"+1{phone}" if not phone.startswith("+") else phone

    try:
        twilio_client.messages.create(body=body, from_=TWILIO_FROM_NUMBER, to=to)
        mark_reminder_sent(appt["id"], hours_ahead)
        log.info(f"Reminder ({hours_ahead}h) sent to {to} for appt #{appt['id']}")
    except Exception as e:
        log.error(f"Reminder SMS failed: {e}")


async def call_summary_job():
    """
    Background job: sends a daily summary email to the business owner at midnight.
    Uses OWNER_EMAIL env var. Falls back to logging if not set.
    """
    while True:
        now = datetime.now()
        # Sleep until next midnight
        tomorrow = (now + timedelta(days=1)).replace(hour=0, minute=0, second=5, microsecond=0)
        wait_s = (tomorrow - now).total_seconds()
        await asyncio.sleep(wait_s)

        try:
            stats = get_dashboard_stats()
            today_str = date.today().isoformat()
            subject = f"Your AI Receptionist Daily Summary — {today_str}"
            body = (
                f"RingDesk Daily Summary for {BUSINESS['name']}\n"
                f"Date: {today_str}\n\n"
                f"Bookings today:       {stats['today']}\n"
                f"This week total:      {stats['week']}\n"
                f"Missed calls today:   {stats['missed_today']}\n"
                f"Callbacks pending:    {stats['callbacks_pending']}\n"
                f"All-time booked:      {stats['total_booked']}\n\n"
                f"View your dashboard: http://localhost:5050/dashboard\n"
                f"— RingDesk AI"
            )

            owner_email = os.environ.get("OWNER_EMAIL", "")
            if owner_email:
                smtp_user = os.environ.get("SMTP_USER", "")
                smtp_pass = os.environ.get("SMTP_PASS", "")
                if smtp_user and smtp_pass:
                    msg = MIMEText(body)
                    msg["Subject"] = subject
                    msg["From"] = smtp_user
                    msg["To"] = owner_email
                    with smtplib.SMTP_SSL("smtp.gmail.com", 465) as server:
                        server.login(smtp_user, smtp_pass)
                        server.send_message(msg)
                    log.info(f"Daily summary emailed to {owner_email}")
                else:
                    log.info(f"Daily summary (SMTP not configured):\n{body}")
            else:
                log.info(f"Daily summary (OWNER_EMAIL not set):\n{body}")
        except Exception as e:
            log.error(f"Call summary job error: {e}")


async def follow_up_job():
    """
    Background job: runs every hour.
    Sends queued follow-up SMS messages (Day 3 and Day 7 after booking).
    """
    while True:
        try:
            due = get_pending_follow_ups()
            for fu in due:
                if not twilio_client or not TWILIO_FROM_NUMBER:
                    mark_follow_up_sent(fu["id"])
                    continue
                phone = fu["phone"]
                to = f"+1{phone}" if not phone.startswith("+") else phone
                try:
                    twilio_client.messages.create(
                        body=fu["message"],
                        from_=TWILIO_FROM_NUMBER,
                        to=to,
                    )
                    mark_follow_up_sent(fu["id"])
                    log.info(f"Follow-up sent to {to}")
                except Exception as e:
                    log.error(f"Follow-up SMS failed to {to}: {e}")
            if due:
                log.info(f"Follow-up job: processed {len(due)} messages")
        except Exception as e:
            log.error(f"Follow-up job error: {e}")
        await asyncio.sleep(3600)


