@app.post("/api/appointments/bulk-confirm")
async def bulk_confirm_appointments(request: Request):
    body = await request.json()
    ids = body.get("ids", [])
    if not ids:
        return JSONResponse({"ok": False, "error": "No IDs provided"}, status_code=400)
    import sqlite3 as _sqlite3
    from appointments import DB_PATH
    conn = _sqlite3.connect(DB_PATH)
    conn.row_factory = _sqlite3.Row
    try:
        placeholders = ",".join("?" * len(ids))
        conn.execute(
            f"UPDATE appointments SET status='confirmed' WHERE id IN ({placeholders})",
            ids,
        )
        conn.commit()
        updated = conn.execute(
            f"SELECT id FROM appointments WHERE id IN ({placeholders}) AND status='confirmed'",
            ids,
        ).fetchall()
        confirmed_ids = [r["id"] for r in updated]
        log.info(f"Bulk confirm: {len(confirmed_ids)} appointments confirmed")
        return {"ok": True, "updated": len(confirmed_ids), "ids": confirmed_ids}
    except Exception as e:
        log.error(f"Bulk confirm error: {e}")
        return JSONResponse({"ok": False, "error": str(e)}, status_code=500)
    finally:
        conn.close()


