@app.get("/api/stats/export")
async def export_stats():
    import sqlite3 as _sqlite3
    from datetime import date as _date

    today = _date.today().isoformat()
    headers = ["id", "client_name", "phone", "service", "date", "time", "status", "created_at"]

    rows = []
    try:
        conn = _sqlite3.connect("appointments.db")
        conn.row_factory = _sqlite3.Row
        raw = conn.execute(
            "SELECT id, client_name, phone, service, date, time, status, created_at FROM appointments ORDER BY date DESC, time DESC"
        ).fetchall()
        conn.close()
        rows = [list(r) for r in raw]
    except Exception as e:
        log.warning(f"Stats export DB error: {e}")

    if not rows:
        rows = [["(no data)", "(no data)", "(no data)", "(no data)", "(no data)", "(no data)", "(no data)", "(no data)"]]

    import io, csv
    buf = io.StringIO()
    writer = csv.writer(buf)
    writer.writerow(headers)
    writer.writerows(rows)
    csv_bytes = buf.getvalue().encode()

    return Response(
        content=csv_bytes,
        media_type="text/csv",
        headers={"Content-Disposition": f'attachment; filename="ringdesk-stats-{today}.csv"'},
    )


