# ── Search ────────────────────────────────────────────────────────────────────

@app.get("/api/search")
async def search(q: str = ""):
    if len(q.strip()) < 2:
        return {"results": [], "count": 0, "error": "Query too short"}

    results = []
    import sqlite3 as _sqlite3

    # Search appointments
    try:
        conn = _sqlite3.connect("appointments.db")
        conn.row_factory = _sqlite3.Row
        like = f"%{q}%"
        rows = conn.execute(
            "SELECT id, client_name, phone, service, date, time, status FROM appointments "
            "WHERE client_name LIKE ? OR phone LIKE ? ORDER BY date DESC LIMIT 50",
            (like, like),
        ).fetchall()
        conn.close()
        for r in rows:
            results.append({"type": "appointment", **dict(r)})
    except Exception as e:
        log.warning(f"Search DB error: {e}")

    # Search callbacks
    try:
        cbs = _load_callbacks()
        for cb in cbs:
            if q.lower() in (cb.get("name", "") + cb.get("phone", "")).lower():
                results.append({"type": "callback", **cb})
    except Exception:
        pass

    return {"results": results, "count": len(results)}


# ── Review requests ───────────────────────────────────────────────────────────

REVIEW_REQUESTS_FILE = "review_requests.json"


def _load_review_requests() -> list:
    try:
        with open(REVIEW_REQUESTS_FILE) as f:
            return json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        return []


@app.post("/api/review-request/send")
async def send_review_request(request: Request):
    body = await request.json()
    phone_raw = body.get("phone", "")
    phone_digits = "".join(c for c in phone_raw if c.isdigit())
    if len(phone_digits) < 10:
        return JSONResponse({"ok": False, "error": "Valid phone required"}, status_code=400)
    platform = body.get("platform", "google").lower()
    if platform not in ("google", "yelp"):
        platform = "google"
    name = body.get("name", "").strip() or "Valued Client"
    rrs = _load_review_requests()
    rrs.append({
        "id": f"rr_{len(rrs) + 1:04d}",
        "phone": phone_digits,
        "name": name,
        "platform": platform,
        "sent_at": datetime.utcnow().isoformat(),
        "status": "queued",
    })
    with open(REVIEW_REQUESTS_FILE, "w") as f:
        json.dump(rrs, f, indent=2)
    log.info(f"Review request queued: {name} {phone_digits} → {platform}")
    return {"ok": True, "message": "Review request queued — SMS will be sent within 5 minutes"}


