# ── Appointment notes ──────────────────────────────────────────────────────────

NOTES_FILE = "appointment_notes.json"


def _load_notes() -> dict:
    try:
        with open(NOTES_FILE) as f:
            return json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        return {}


@app.get("/api/appointments/{appt_id}/notes")
async def get_appointment_notes(appt_id: int):
    all_notes = _load_notes()
    key = str(appt_id)
    notes = all_notes.get(key, [])
    return {"id": appt_id, "notes": notes}


@app.post("/api/appointments/{appt_id}/notes")
async def add_appointment_note(appt_id: int, request: Request):
    body = await request.json()
    text = body.get("text", "").strip()[:500]
    if not text:
        return JSONResponse({"ok": False, "error": "Note text required"}, status_code=400)
    all_notes = _load_notes()
    key = str(appt_id)
    if key not in all_notes:
        all_notes[key] = []
    note = {
        "id": f"note_{appt_id}_{len(all_notes[key]) + 1}",
        "text": text,
        "created_at": datetime.utcnow().isoformat(),
    }
    all_notes[key].append(note)
    with open(NOTES_FILE, "w") as f:
        json.dump(all_notes, f, indent=2)
    log.info(f"Note added to appointment {appt_id}")
    return {"ok": True, "note": note}


# ── Calls CSV export ──────────────────────────────────────────────────────────

@app.get("/api/export/calls")
async def export_calls():
    import sqlite3 as _sqlite3, io, csv
    from datetime import date as _date

    today = _date.today().isoformat()
    headers = ["date", "time", "type", "client_name", "phone", "service", "status", "notes"]
    rows = []

    # From appointments DB
    try:
        conn = _sqlite3.connect("appointments.db")
        conn.row_factory = _sqlite3.Row
        appts = conn.execute(
            "SELECT date, time, client_name, phone, service, status FROM appointments ORDER BY date DESC, time DESC"
        ).fetchall()
        conn.close()
        all_notes = _load_notes()
        for a in appts:
            appt_id = str(a["status"])  # we don't have id in this query; get fresh
            rows.append([
                a["date"], a["time"], "booking",
                a["client_name"], a["phone"], a["service"], a["status"], "",
            ])
    except Exception as e:
        log.warning(f"Export calls DB error: {e}")

    # From callbacks_pending.json
    try:
        cbs = _load_callbacks()
        for cb in cbs:
            rows.append([
                cb.get("created_at", "")[:10],
                cb.get("created_at", "")[11:16],
                "callback",
                cb.get("name", ""),
                cb.get("phone", ""),
                "",
                cb.get("status", "pending"),
                cb.get("reason", ""),
            ])
    except Exception:
        pass

    if not rows:
        rows = [["2026-04-17", "14:00", "booking", "(example)", "5555550100", "Fade", "confirmed", ""]]

    buf = io.StringIO()
    writer = csv.writer(buf)
    writer.writerow(headers)
    writer.writerows(rows)

    return Response(
        content=buf.getvalue().encode(),
        media_type="text/csv",
        headers={"Content-Disposition": f'attachment; filename="ringdesk-calls-{today}.csv"'},
    )


