@app.get("/api/goals")
async def get_goals():
    goals = _load_goals()
    # Query SQLite for this month's progress
    import sqlite3 as _sqlite3
    from appointments import DB_PATH
    import datetime as _dt
    month_start = _dt.date.today().replace(day=1).isoformat()
    try:
        conn = _sqlite3.connect(DB_PATH)
        conn.row_factory = _sqlite3.Row
        total = conn.execute(
            "SELECT COUNT(*) as c FROM appointments WHERE date >= ?", (month_start,)
        ).fetchone()["c"]
        noshows = conn.execute(
            "SELECT COUNT(*) as c FROM appointments WHERE date >= ? AND status='no-show'", (month_start,)
        ).fetchone()["c"]
        conn.close()
        bookings_progress = total
        noshow_pct = round((noshows / total * 100) if total > 0 else 0, 1)
    except Exception:
        bookings_progress = 0
        noshow_pct = 0.0
    revenue_mock = bookings_progress * 22  # ~$22 avg ticket
    return {
        "goals": goals,
        "progress": {
            "monthly_bookings": bookings_progress,
            "no_show_rate": noshow_pct,
            "revenue": revenue_mock,
        }
    }

