@app.get("/api/appointments/stats")
async def appointments_stats():
    import sqlite3 as _sqlite3
    from appointments import DB_PATH
    import datetime as _dt
    today = _dt.date.today().isoformat()
    month_start = _dt.date.today().replace(day=1).isoformat()
    try:
        conn = _sqlite3.connect(DB_PATH)
        conn.row_factory = _sqlite3.Row
        total = conn.execute("SELECT COUNT(*) as c FROM appointments").fetchone()["c"]
        confirmed = conn.execute("SELECT COUNT(*) as c FROM appointments WHERE status='confirmed'").fetchone()["c"]
        pending = conn.execute("SELECT COUNT(*) as c FROM appointments WHERE status='pending'").fetchone()["c"]
        noshows = conn.execute("SELECT COUNT(*) as c FROM appointments WHERE status='no-show'").fetchone()["c"]
        cancelled = conn.execute("SELECT COUNT(*) as c FROM appointments WHERE status='cancelled'").fetchone()["c"]
        today_count = conn.execute("SELECT COUNT(*) as c FROM appointments WHERE date=?", (today,)).fetchone()["c"]
        month_count = conn.execute("SELECT COUNT(*) as c FROM appointments WHERE date>=?", (month_start,)).fetchone()["c"]
        conn.close()
    except Exception:
        total = confirmed = pending = noshows = cancelled = today_count = month_count = 0
    noshow_rate = round((noshows / total * 100) if total > 0 else 0, 1)
    return {
        "total": total, "confirmed": confirmed, "pending": pending,
        "no_shows": noshows, "cancelled": cancelled,
        "today": today_count, "this_month": month_count,
        "no_show_rate": noshow_rate,
    }


