@app.put("/api/appointments/reschedule/{appt_id}")
async def reschedule_appointment(appt_id: int, request: Request):
    body = await request.json()
    new_date = body.get("new_date")
    new_time = body.get("new_time")
    if not new_date or not new_time:
        return JSONResponse({"error": "new_date and new_time required"}, status_code=400)
    import sqlite3 as _sqlite3
    from appointments import DB_PATH
    conn = _sqlite3.connect(DB_PATH)
    conn.row_factory = _sqlite3.Row
    conn.execute(
        "UPDATE appointments SET date=?, time=?, status='confirmed' WHERE id=?",
        (new_date, new_time, appt_id)
    )
    conn.commit()
    row = conn.execute("SELECT * FROM appointments WHERE id=?", (appt_id,)).fetchone()
    conn.close()
    if not row:
        return JSONResponse({"error": "appointment not found"}, status_code=404)
    return {"ok": True, "appointment": dict(row)}

