@app.post("/api/promo-codes")
async def add_promo(request: Request):
    body = await request.json()
    code = str(body.get("code","")).upper().strip()
    import re as _re
    if not _re.match(r'^[A-Z0-9]{2,20}$', code):
        return JSONResponse({"error": "Code must be 2–20 uppercase letters/numbers"}, status_code=400)
    promos = _load_promos()
    if any(p["code"] == code for p in promos):
        return JSONResponse({"error": "Code already exists"}, status_code=409)
    entry = {
        "code": code,
        "discount_type": body.get("discount_type","percent"),
        "discount_value": float(body.get("discount_value", 10)),
        "uses_remaining": int(body.get("uses_remaining", 100)),
        "expires_at": body.get("expires_at",""),
        "active": True,
    }
    promos.append(entry)
    _save_promos(promos)
    return {"ok": True, "entry": entry}

