# ── Appointments Calendar ──────────────────────────────────────────────────────
@app.get("/api/appointments/calendar")
async def appointments_calendar(month: str = ""):
    import sqlite3 as _sqlite3
    from appointments import DB_PATH
    import datetime as _dt
    if not month:
        month = _dt.date.today().strftime("%Y-%m")
    try:
        year, mon = map(int, month.split("-"))
    except Exception:
        year, mon = _dt.date.today().year, _dt.date.today().month
    # first and last day of month
    first = _dt.date(year, mon, 1)
    if mon == 12:
        last = _dt.date(year + 1, 1, 1) - _dt.timedelta(days=1)
    else:
        last = _dt.date(year, mon + 1, 1) - _dt.timedelta(days=1)
    try:
        conn = _sqlite3.connect(DB_PATH)
        conn.row_factory = _sqlite3.Row
        rows = conn.execute(
            "SELECT * FROM appointments WHERE date >= ? AND date <= ? ORDER BY time",
            (first.isoformat(), last.isoformat())
        ).fetchall()
        conn.close()
        appts = [dict(r) for r in rows]
    except Exception:
        appts = []
    # Group by date
    days: dict = {}
    for a in appts:
        d = a["date"]
        days.setdefault(d, []).append(a)
    return {"month": month, "days": days, "total": len(appts)}

@app.get("/calendar", response_class=HTMLResponse)
async def calendar_page():
    return FileResponse("calendar.html")


