@app.get("/api/export/appointments")
async def export_appointments_csv():
    import sqlite3 as _sqlite3
    from appointments import DB_PATH
    import io as _io
    import csv as _csv
    try:
        conn = _sqlite3.connect(DB_PATH)
        conn.row_factory = _sqlite3.Row
        rows = conn.execute(
            "SELECT id, name, phone, service, staff, date, time, status FROM appointments ORDER BY date, time"
        ).fetchall()
        conn.close()
    except Exception:
        rows = []
    buf = _io.StringIO()
    writer = _csv.writer(buf)
    writer.writerow(["id", "name", "phone", "service", "staff", "date", "time", "status"])
    for r in rows:
        keys = r.keys() if hasattr(r, 'keys') else []
        staff = r["staff"] if "staff" in keys else ""
        writer.writerow([r["id"], r["name"], r["phone"], r["service"], staff, r["date"], r["time"], r["status"]])
    csv_bytes = buf.getvalue().encode()
    return Response(
        content=csv_bytes,
        media_type="text/csv",
        headers={"Content-Disposition": "attachment; filename=appointments.csv"}
    )


