# ── Retention Cohorts ──────────────────────────────────────────────────────────
@app.get("/api/analytics/retention")
async def analytics_retention():
    import datetime as _dt, random as _rnd
    _rnd.seed(42)
    today = _dt.date.today()
    cohorts = []
    for i in range(5, -1, -1):
        # month i months ago
        m = today.month - i
        y = today.year
        while m <= 0: m += 12; y -= 1
        label = _dt.date(y, m, 1).strftime("%b %Y")
        initial = _rnd.randint(18, 35)
        m1 = round(initial * _rnd.uniform(0.68, 0.80))
        m2 = round(m1     * _rnd.uniform(0.72, 0.85)) if i >= 2 else None
        m3 = round(m2     * _rnd.uniform(0.75, 0.88)) if (m2 is not None and i >= 3) else None
        cohorts.append({"month": label, "initial": initial, "m1": m1, "m2": m2, "m3": m3})
    return {"cohorts": cohorts}

