# ── Payouts ────────────────────────────────────────────────────────────────────
@app.get("/api/payouts")
async def get_payouts():
    import datetime as _dt
    today = _dt.date.today()
    payouts = []
    for i in range(5, -1, -1):
        m = today.month - i
        y = today.year
        while m <= 0: m += 12; y -= 1
        period = _dt.date(y, m, 1).strftime("%B %Y")
        is_current = (m == today.month and y == today.year)
        is_prev = (i == 1)
        # Escalating amounts
        base = 3200 + (5 - i) * 420
        amount = base if not is_current else round(base * (today.day / 30), 2)
        transactions = int(base / 32)
        if is_current:
            status = "pending"
            paid_at = None
        elif is_prev:
            status = "processing"
            paid_at = None
        else:
            status = "paid"
            last_day = _dt.date(y, m + 1 if m < 12 else 1, 1) - _dt.timedelta(days=1) if m < 12 else _dt.date(y+1, 1, 1) - _dt.timedelta(days=1)
            paid_at = (last_day + _dt.timedelta(days=3)).isoformat()
        payouts.append({"period": period, "amount": amount, "status": status, "transactions": transactions, "paid_at": paid_at})
    ytd = sum(p["amount"] for p in payouts if p["status"] == "paid")
    return {"payouts": payouts, "ytd_paid": round(ytd, 2)}

