@app.get("/api/sms-log")
async def get_sms_log():
    now = datetime.now()
    def _ago(m): return (now - timedelta(minutes=m)).isoformat()
    names = ["Marcus T.","Aisha M.","Darius W.","Keisha R.","Tony R.","Jordan B.","Priya S.","Carlos M.","Diane F.","Reggie T."]
    phones = ["(555) 210-3847","(555) 847-2201","(555) 404-9921","(555) 312-0055","(555) 718-4433","(555) 626-1177","(555) 503-8844","(555) 415-6622","(555) 212-9900","(555) 305-7711"]
    msgs_out = [
        "Hi {n}! Reminder: your appointment is tomorrow at {t}. Reply CANCEL to cancel.",
        "Thanks for visiting! We hope to see you again soon. Book your next appt at ringdesk.ai",
        "Hi {n}, your appointment has been confirmed for {t}. See you then!",
        "A slot just opened up this Friday at 3pm — want it? Reply YES to book.",
        "Your barber Jordan is running 10 min late today. See you soon!",
    ]
    msgs_in = [
        "YES please book me in",
        "Can I reschedule to Friday?",
        "CANCEL",
        "What time is my appointment?",
        "Is Jordan available Saturday?",
    ]
    import random; random.seed(99)
    entries = []
    for i in range(30):
        direction = "outbound" if i % 3 != 2 else "inbound"
        idx = i % 10
        mins = i * 47 + random.randint(1, 30)
        body_raw = msgs_out[i % len(msgs_out)].format(n=names[idx].split()[0], t=f"{9 + (i%8)}:{('00' if i%2==0 else '30')}am") if direction == "outbound" else msgs_in[i % len(msgs_in)]
        body = body_raw[:80]
        statuses = ["delivered","delivered","delivered","failed","pending"]
        entries.append({
            "id": f"sms{i+1}",
            "to_phone": phones[idx],
            "direction": direction,
            "body": body,
            "status": statuses[i % len(statuses)],
            "sent_at": _ago(mins),
        })
    entries.sort(key=lambda x: x["sent_at"], reverse=True)
    return {"messages": entries}

