@app.get("/api/bookings/upcoming")
async def get_upcoming_bookings():
    try:
        import sqlite3 as _sqlite3
        from appointments import DB_PATH
        conn = _sqlite3.connect(DB_PATH)
        conn.row_factory = _sqlite3.Row
        rows = conn.execute(
            "SELECT * FROM appointments WHERE start_time >= datetime('now') ORDER BY start_time LIMIT 10"
        ).fetchall()
        conn.close()
        if rows:
            result = []
            for r in rows:
                keys = r.keys() if hasattr(r, 'keys') else []
                result.append({
                    "client_name": r["client_name"] if "client_name" in keys else "Client",
                    "phone": r["phone"] if "phone" in keys else "",
                    "service": r["service"] if "service" in keys else "Haircut",
                    "staff": r["staff"] if "staff" in keys else "Jordan",
                    "start_time": r["start_time"] if "start_time" in keys else "",
                    "status": r["status"] if "status" in keys else "confirmed",
                })
            return {"bookings": result}
    except Exception:
        pass
    # Mock fallback
    now = datetime.now()
    def _appt(h, m, name, phone, svc, staff, status="confirmed"):
        t = now.replace(hour=h, minute=m, second=0, microsecond=0)
        if t < now:
            t += timedelta(days=1)
        return {"client_name": name, "phone": phone, "service": svc, "staff": staff, "start_time": t.isoformat(), "status": status}
    bookings = [
        _appt(10, 0,  "Marcus T.",  "(555) 210-3847", "Haircut + Beard",  "Jordan"),
        _appt(10, 30, "Aisha M.",   "(555) 847-2201", "Color + Cut",      "Priya"),
        _appt(11, 0,  "Darius W.",  "(555) 404-9921", "Fade",             "Jordan"),
        _appt(11, 30, "Keisha R.",  "(555) 312-0055", "Blow-dry + Style", "Priya"),
        _appt(13, 0,  "Tony R.",    "(555) 718-4433", "Hot Towel Shave",  "Jordan", "pending"),
        _appt(14, 0,  "Carlos M.",  "(555) 626-1177", "Haircut",          "Dante"),
        _appt(14, 30, "Diane F.",   "(555) 503-8844", "Braids",           "Priya"),
        _appt(15, 0,  "Reggie T.",  "(555) 415-6622", "Fade + Design",    "Jordan"),
        _appt(16, 0,  "Priya S.",   "(555) 212-9900", "Cut + Condition",  "Priya", "pending"),
        _appt(17, 0,  "Jordan B.",  "(555) 305-7711", "Beard Trim",       "Dante"),
    ]
    bookings.sort(key=lambda x: x["start_time"])
    return {"bookings": bookings}

