# ── Capacity ───────────────────────────────────────────────────────────────────
@app.get("/api/capacity")
async def get_capacity():
    import random as _random
    _random.seed(42)
    capacity_per_hour = 3  # 3 chairs
    by_hour = []
    for h in range(24):
        if h < 9 or h >= 19:
            booked, cap = 0, 0
        else:
            # Peak pattern: lunch (12-14) and after-work (16-18)
            base = 0.3 + 0.5 * (1 - abs(h - 13) / 5) + 0.4 * (1 - abs(h - 17) / 4)
            base = max(0.1, min(0.95, base + _random.uniform(-0.1, 0.1)))
            cap = capacity_per_hour
            booked = round(cap * base)
        pct = round(booked / cap * 100, 1) if cap > 0 else 0.0
        by_hour.append({"hour": h, "booked": booked, "capacity": cap, "utilization_pct": pct})

    days = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
    day_utils = [52.0, 68.0, 71.0, 74.0, 89.0, 94.0, 31.0]
    by_day = [{"day": d, "avg_utilization": u} for d, u in zip(days, day_utils)]

    open_hours = [h for h in by_hour if h["capacity"] > 0]
    peak_hour = max(open_hours, key=lambda h: h["utilization_pct"])["hour"]
    avg_util = round(sum(h["utilization_pct"] for h in open_hours) / len(open_hours), 1) if open_hours else 0.0

    return {
        "by_hour": by_hour,
        "by_day": by_day,
        "peak_hour": peak_hour,
        "busiest_day": "Saturday",
        "avg_daily_utilization": avg_util,
    }

