@app.get("/api/export/revenue")
async def export_revenue_csv():
    import io, csv as _csv
    now = datetime.now()
    rows = []
    for i in range(5, -1, -1):
        d = (now.replace(day=1) - timedelta(days=i*28)).replace(day=1)
        label = d.strftime("%Y-%m")
        gross = 4200 + i * 380 + (i % 3) * 120
        net = round(gross * 0.927, 2)
        appts = 68 + i * 6
        rows.append((label, gross, net, appts))
    buf = io.StringIO()
    w = _csv.writer(buf)
    w.writerow(["Month", "Gross Revenue", "Net Revenue", "Appointment Count"])
    w.writerows(rows)
    from fastapi.responses import Response as _Resp
    return _Resp(content=buf.getvalue(), media_type="text/csv", headers={"Content-Disposition": "attachment; filename=ringdesk_revenue.csv"})


