# ── Availability ───────────────────────────────────────────────────────────────
@app.get("/api/availability")
async def get_availability(date: str = "", service_id: str = ""):
    import random as _r
    _r.seed(hash(date + service_id) % 9999)
    slots = []
    staff_pool = ["Jordan", "Priya", "Dante"]
    for hour in range(9, 19):
        for minute in [0, 30]:
            t = f"{hour:02d}:{minute:02d}"
            disp = f"{hour if hour <= 12 else hour-12}:{minute:02d}{'am' if hour < 12 else 'pm'}"
            available = _r.random() > 0.35
            staff = staff_pool[_r.randint(0, 2)] if available else ""
            slots.append({"time": t, "display": disp, "staff_name": staff, "available": available})
    return {"date": date, "slots": slots}

@app.get("/availability", response_class=HTMLResponse)
async def availability_page():
    return FileResponse("availability.html")


# ── Monthly Report ─────────────────────────────────────────────────────────────
@app.get("/api/reports/monthly")
async def get_monthly_report(month: str = ""):
    if not month:
        month = datetime.now().strftime("%Y-%m")
    import random as _r
    _r.seed(hash(month) % 9999)
    base_appts = 160 + _r.randint(0, 60)
    revenue = base_appts * (_r.randint(55, 75))
    new_clients = _r.randint(18, 35)
    returning = base_appts - new_clients
    no_shows = _r.randint(8, 20)
    return {
        "month": month,
        "total_appointments": base_appts,
        "total_revenue": revenue,
        "avg_ticket": round(revenue / base_appts, 2),
        "new_clients": new_clients,
        "returning_clients": returning,
        "no_show_count": no_shows,
        "top_service": "Haircut + Beard",
        "top_staff": "Jordan",
        "busiest_day": "Saturday",
        "review_count": _r.randint(4, 14),
        "avg_rating": round(4.2 + _r.uniform(0, 0.7), 1),
        "sms_sent": base_appts * 2 + _r.randint(20, 60),
    }

