# ── Client Directory ───────────────────────────────────────────────────────────
@app.get("/api/clients")
async def get_clients(page: int = 1, limit: int = 20, search: str = "", tag: str = ""):
    try:
        import sqlite3 as _sql
        conn = _sql.connect(DB_PATH)
        cur = conn.cursor()
        q = "SELECT c.id, c.name, c.phone, c.created_at, COUNT(a.id), COALESCE(SUM(a.price),0), MAX(a.appointment_time) FROM clients c LEFT JOIN appointments a ON a.client_id=c.id"
        params = []
        if search:
            q += " WHERE (c.name LIKE ? OR c.phone LIKE ?)"
            params += [f"%{search}%", f"%{search}%"]
        q += " GROUP BY c.id ORDER BY MAX(a.appointment_time) DESC NULLS LAST"
        cur.execute(q, params)
        rows = cur.fetchall()
        conn.close()
        clients = [{"id": r[0], "name": r[1], "phone": r[2], "member_since": r[3], "visit_count": r[4], "total_spent": round(r[5], 2), "last_visit": r[6], "tags": []} for r in rows]
    except Exception:
        clients = [
            {"id": "c1", "name": "Marcus Webb", "phone": "+15551234001", "member_since": "2024-06-15", "visit_count": 18, "total_spent": 1170, "last_visit": "2026-04-10", "tags": ["VIP", "Regular"]},
            {"id": "c2", "name": "Diana Chen", "phone": "+15551234002", "member_since": "2024-09-20", "visit_count": 12, "total_spent": 1800, "last_visit": "2026-04-08", "tags": ["Color Client"]},
            {"id": "c3", "name": "James Okoye", "phone": "+15551234003", "member_since": "2025-01-10", "visit_count": 8, "total_spent": 200, "last_visit": "2026-04-05", "tags": []},
            {"id": "c4", "name": "Sofia Reyes", "phone": "+15551234004", "member_since": "2023-11-05", "visit_count": 31, "total_spent": 1550, "last_visit": "2026-04-12", "tags": ["VIP", "Regular"]},
            {"id": "c5", "name": "Tyler Brooks", "phone": "+15551234005", "member_since": "2025-03-14", "visit_count": 5, "total_spent": 325, "last_visit": "2026-04-01", "tags": []},
            {"id": "c6", "name": "Aisha Thompson", "phone": "+15551234006", "member_since": "2024-02-28", "visit_count": 22, "total_spent": 3300, "last_visit": "2026-04-09", "tags": ["VIP"]},
        ]
    offset = (page - 1) * limit
    page_clients = clients[offset:offset + limit]
    return {"clients": page_clients, "total": len(clients), "page": page, "has_more": offset + limit < len(clients)}

