# ── Busiest Times Heatmap ─────────────────────────────────────────────────────
@app.get("/api/analytics/busiest-times")
async def get_busiest_times():
    import random
    data = []
    peak_hours = {1: [10,11,14,15], 2: [9,10,11,15,16], 3: [10,11,12,14,15,16],
                  4: [11,12,14,15,16], 5: [10,11,12,14,15,16,17], 6: [9,10,11,12,13,14,15,16]}
    for day in range(7):
        for hour in range(7, 24):
            base = 0
            if day in peak_hours and hour in peak_hours.get(day, []):
                base = random.randint(4, 12)
            elif day < 6 and 9 <= hour <= 17:
                base = random.randint(1, 4)
            count = max(0, base + random.randint(-1, 2))
            rev = round(count * random.uniform(45, 85), 2) if count else 0
            if count > 0:
                data.append({"hour": hour, "day": day, "count": count, "revenue": rev})
    return {"data": data, "hours_range": [7, 23]}

