@app.get("/api/call-log")
async def get_call_log(outcome: str = "", limit: int = 50):
    import random
    OUTCOMES = ["booked", "info", "canceled", "voicemail", "escalated"]
    INTENTS = ["Book Appointment", "Reschedule", "Cancel Booking", "Hours & Pricing", "Directions", "Inquiry", "Speak to Staff"]
    STAFF = ["Jordan Lee", "Priya Sharma", "Dante Cruz", None]
    calls = []
    for i in range(min(limit, 40)):
        oc = random.choice(OUTCOMES)
        if outcome and oc != outcome:
            oc = outcome
        calls.append({
            "call_id": f"CA{random.randint(100000,999999)}",
            "caller_number": f"***-***-{random.randint(1000,9999)}",
            "timestamp": (datetime.now() - timedelta(hours=random.randint(0, 72), minutes=random.randint(0, 59))).isoformat(),
            "duration_seconds": random.randint(15, 240),
            "outcome": oc,
            "intent": random.choice(INTENTS),
            "staff_assigned": random.choice(STAFF),
            "transcript_summary": f"Caller inquired about {random.choice(INTENTS).lower()}. AI handled successfully. " + ("Appointment booked for next available slot." if oc == "booked" else "Caller was provided information." if oc == "info" else "Appointment was canceled." if oc == "canceled" else "Call escalated to staff." if oc == "escalated" else "Left voicemail for callback."),
        })
    calls.sort(key=lambda c: c["timestamp"], reverse=True)
    return {"calls": calls, "total": len(calls)}

