# ── Client Retention ──────────────────────────────────────────────────────────
@app.get("/api/analytics/client-retention")
async def get_client_retention():
    import random
    total = random.randint(320, 750)
    r30 = int(total * random.uniform(.42, .58))
    r90 = int(total * random.uniform(.62, .78))
    r180 = int(total * random.uniform(.75, .88))
    lapsed = total - r180
    cohorts = []
    now = datetime.now()
    for i in range(6, 0, -1):
        mo = (now.month - i - 1) % 12 + 1
        yr = now.year if now.month - i > 0 else now.year - 1
        nc = random.randint(18, 52)
        cohorts.append({"month": f"{yr}-{mo:02d}", "new_clients": nc,
                         "retained_next_month": int(nc * random.uniform(.48, .72))})
    return {"total_clients": total, "retained_30d": r30, "retained_90d": r90,
            "retained_180d": r180, "lapsed": lapsed,
            "avg_days_between_visits": random.randint(18, 35),
            "cohort_data": cohorts}

