@app.get("/api/analytics/revenue-forecast")
async def get_revenue_forecast():
    import random
    now = datetime.now()
    data = []
    base = random.randint(8000, 14000)
    for i in range(-3, 4):
        mo_dt = datetime(now.year, now.month, 1)
        # Shift months
        total_months = mo_dt.month + i
        yr = mo_dt.year + (total_months - 1) // 12
        mo = (total_months - 1) % 12 + 1
        label = f"{yr}-{mo:02d}"
        trend = base + i * random.randint(200, 600)
        noise = random.randint(-400, 400)
        actual = round(trend + noise, 2) if i <= 0 else None
        forecast = round(trend, 2)
        spread = random.randint(600, 1400)
        data.append({"month": label, "actual": actual, "forecast": forecast,
                      "lower_bound": round(forecast - spread, 2),
                      "upper_bound": round(forecast + spread, 2)})
    return {"forecast": data}

