@app.get("/api/analytics/cancellation-reasons")
async def get_cancellation_reasons():
    import random
    reasons_pool = [
        "Schedule conflict", "Personal emergency", "Forgot appointment",
        "Found another shop", "Price concern", "Long wait time",
        "Staff not available", "Weather / travel", "Illness"
    ]
    total = random.randint(80, 140)
    counts = sorted([random.randint(5, 35) for _ in reasons_pool], reverse=True)
    total_count = sum(counts)
    reasons = [{"reason": r, "count": c, "pct_of_total": round(c / total_count * 100, 1)} for r, c in zip(reasons_pool, counts)]
    months = []
    for i in range(3, 0, -1):
        import datetime
        d = datetime.date.today().replace(day=1) - datetime.timedelta(days=i*28)
        months.append({"month": d.strftime("%b %Y"), "cancellation_rate_pct": round(random.uniform(8, 22), 1)})
    return {"reasons": reasons, "trend": months}

