    import random, datetime
    today = datetime.date.today()
    days = []
    for i in range(29, -1, -1):
        d = today - datetime.timedelta(days=i)
        dow = d.weekday()  # 0=Mon, 6=Sun
        if dow >= 5:  # weekend higher
            rev = round(random.uniform(380, 820), 2)
            cnt = random.randint(8, 18)
        elif dow == 0:  # Monday slower
            rev = round(random.uniform(120, 340), 2)
            cnt = random.randint(3, 9)
        else:
            rev = round(random.uniform(220, 620), 2)
            cnt = random.randint(5, 14)
        days.append({"date": d.isoformat(), "revenue": rev, "appointment_count": cnt})
    return {"days": days}

