STAFF_MOCK = {
    "1": "Marcus J.", "2": "Destiny R.", "3": "Carlos M.", "4": "Aisha T.",
}

@app.get("/api/staff/{staff_id}/schedule")
async def get_staff_schedule(staff_id: str):
    import random, datetime
    name = STAFF_MOCK.get(staff_id, f"Staff {staff_id}")
    today = datetime.date.today()
    monday = today - datetime.timedelta(days=today.weekday())
    services = ["Haircut", "Color", "Beard Trim", "Blowout", "Manicure", "Facial"]
    clients = ["Jordan T.", "Simone K.", "Marcus B.", "Aaliyah R.", "Devon H.",
               "Keisha M.", "Trevon L.", "Priya S.", "Carlos W.", "Nia J."]
    statuses = ["confirmed", "confirmed", "pending", "arrived", "completed"]
    days = []
    for i in range(7):
        d = monday + datetime.timedelta(days=i)
        is_off = d.weekday() == 6  # Sunday off
        appts = []
        if not is_off:
            count = random.randint(2, 6)
            hour = 9
            for _ in range(count):
                appts.append({
                    "time": f"{hour:02d}:{random.choice([0,30]):02d}",
                    "client": random.choice(clients),
                    "service": random.choice(services),
                    "status": random.choice(statuses),
                })
                hour += random.randint(1, 2)
                if hour > 17:
                    break
        days.append({
            "date": d.isoformat(),
            "day_name": d.strftime("%a"),
            "is_off": is_off,
            "appointments": appts,
        })
    return {"staff_name": name, "staff_id": staff_id, "days": days}

