@app.get("/api/clients/{client_id}/history")
async def get_client_history(client_id: str):
    import random, datetime
    mock_names = {
        "1": ("Aaliyah Brooks", "(310) 555-2847"),
        "2": ("Marcus Thompson", "(323) 555-9134"),
        "3": ("Simone Washington", "(424) 555-0671"),
    }
    name, phone = mock_names.get(client_id, (f"Client {client_id}", "(555) 000-0000"))
    services = ["Haircut", "Color", "Beard Trim", "Blowout", "Manicure", "Facial"]
    staff_list = ["Marcus J.", "Destiny R.", "Carlos M.", "Aisha T."]
    statuses = ["completed", "completed", "completed", "completed", "no-show", "canceled"]
    today = datetime.date.today()
    visits = random.randint(8, 24)
    appts = []
    for i in range(visits):
        days_ago = random.randint(i * 14, i * 14 + 20)
        d = today - datetime.timedelta(days=days_ago)
        amount = round(random.uniform(35, 120), 2)
        status = random.choice(statuses)
        appts.append({
            "date": d.isoformat(),
            "service": random.choice(services),
            "staff": random.choice(staff_list),
            "amount": amount if status == "completed" else 0,
            "status": status,
            "rating": random.randint(3, 5) if status == "completed" else None,
        })
    appts.sort(key=lambda x: x["date"], reverse=True)
    lifetime = sum(a["amount"] for a in appts)
    return {
        "client_name": name,
        "phone": phone,
        "total_visits": visits,
        "lifetime_revenue": round(lifetime, 2),
        "appointments": appts,
    }

