async def get_call_outcomes_trend():
    import random, datetime
    today = datetime.date.today()
    weeks = []
    for i in range(7, -1, -1):
        monday = today - datetime.timedelta(days=today.weekday() + i * 7)
        total = random.randint(55, 120)
        booked = int(total * random.uniform(.42, .62))
        info = int(total * random.uniform(.12, .22))
        canceled = int(total * random.uniform(.06, .12))
        voicemail = int(total * random.uniform(.05, .12))
        escalated = total - booked - info - canceled - voicemail
        weeks.append({
            "week_label": monday.strftime("%m/%d"),
            "booked": booked,
            "info": info,
            "canceled": canceled,
            "voicemail": voicemail,
            "escalated": max(escalated, 0),
        })
    return {"weeks": weeks}

