@app.get("/api/analytics/revenue-by-staff")
async def get_revenue_by_staff():
    import random
    names = ["Marcus J.", "Destiny R.", "Carlos M.", "Aisha T.", "Jordan B."]
    total_rev = random.randint(14000, 26000)
    staff = []
    remaining = total_rev
    for i, name in enumerate(names):
        if i == len(names) - 1:
            rev = remaining
        else:
            pct = random.uniform(0.12, 0.28)
            rev = round(remaining * pct, 2)
            remaining -= rev
        appts = random.randint(18, 54)
        staff.append({
            "staff_name": name,
            "revenue": rev,
            "appointments": appts,
            "avg_ticket": round(rev / appts, 2),
            "pct_of_total": 0,
        })
    for s in staff:
        s["pct_of_total"] = round(s["revenue"] / total_rev * 100, 1)
    staff.sort(key=lambda x: x["revenue"], reverse=True)
    return {"staff": staff, "total_revenue": total_rev}

