@app.get("/api/analytics/peak-hours")
async def get_peak_hours():
    import random
    cells = []
    peak_intensity = 0
    for dow in range(7):  # 0=Mon
        for hour in range(6, 22):  # 6am-9pm
            if 9 <= hour <= 18 and dow < 5:
                intensity = random.randint(30, 95)
            elif 9 <= hour <= 18 and dow >= 5:
                intensity = random.randint(55, 100)
            elif 7 <= hour < 9 or 19 <= hour <= 20:
                intensity = random.randint(5, 35)
            else:
                intensity = random.randint(0, 10)
            cells.append({"day_of_week": dow, "hour": hour, "intensity": intensity})
            if intensity > peak_intensity:
                peak_intensity = intensity
    return {"cells": cells, "peak_intensity": peak_intensity}

