GIFT_CARDS_FILE = "gift_cards.json"

def _load_gift_cards():
    try:
        with open(GIFT_CARDS_FILE) as f:
            return json.load(f)
    except FileNotFoundError:
        import uuid as _uuid, random, string
        random.seed(17)
        statuses = ["active","active","active","active","active","used","used","active","expired","active"]
        purchasers = ["Linda M.","Robert K.","Aisha B.","Carlos V.","Tanya W.",
                      "Kevin O.","Priya S.","Marcus T.","Janelle R.","Devon W."]
        recipients = ["Mom","Dad","Sister","Friend","Wife","Self","Partner","Daughter","Son","Grandma"]
        cards = []
        for i in range(10):
            code = "GC-" + "".join(random.choices(string.ascii_uppercase + string.digits, k=8))
            initial = random.choice([25, 50, 75, 100, 150])
            status = statuses[i]
            remaining = 0 if status == "used" else (initial if status == "expired" else random.randint(0, initial))
            cards.append({
                "id": str(_uuid.uuid4()),
                "code": code,
                "initial_value": initial,
                "remaining_value": remaining,
                "purchaser_name": purchasers[i],
                "recipient_name": recipients[i],
                "status": status,
                "purchased_at": (_dt.datetime.now() - _dt.timedelta(days=random.randint(5,120))).isoformat(),
            })
        return cards

def _save_gift_cards(data):
    with open(GIFT_CARDS_FILE, "w") as f:
        json.dump(data, f)

