async def get_gift_cards():
    return {"gift_cards": _load_gift_cards()}

@app.post("/api/gift-cards")
async def create_gift_card(payload: dict):
    import uuid as _uuid, string, random
    cards = _load_gift_cards()
    code = "GC-" + "".join(random.choices(string.ascii_uppercase + string.digits, k=8))
    card = {
        "id": str(_uuid.uuid4()),
        "code": code,
        "initial_value": payload.get("initial_value", 50),
        "remaining_value": payload.get("initial_value", 50),
        "purchaser_name": payload.get("purchaser_name", ""),
        "recipient_name": payload.get("recipient_name", ""),
        "status": "active",
        "purchased_at": _dt.datetime.now().isoformat(),
    }
    cards.append(card)
    _save_gift_cards(cards)
    return {"ok": True, "gift_card": card}

