    bucket_counts = [random.randint(20, 80) for _ in buckets]
    distribution = [{"bucket_label": b[0], "count": bucket_counts[i]} for i, b in enumerate(buckets)]
    trend = []
    for i in range(13, -1, -1):
        d = today - _dt.timedelta(days=i)
        trend.append({"date": d.isoformat(), "avg_sec": avg + random.randint(-20, 20)})
    return {"avg_duration_sec": avg, "by_outcome": by_outcome, "distribution": distribution, "trend": trend}

