@app.get("/api/analytics/revenue-trend")
async def get_revenue_trend():
    import random
    random.seed(43)
    today = _dt.date.today()
    daily = []
    best_day = None
    best_rev = 0
    monthly_total = 0
    for i in range(29, -1, -1):
        d = today - _dt.timedelta(days=i)
        is_sat = d.weekday() == 5
        is_sun = d.weekday() == 6
        base = 720 if is_sat else (480 if is_sun else 520)
        rev = base + random.randint(-150, 200)
        rev = max(280, rev)
        appts = max(4, round(rev / (random.randint(55, 75))))
        daily.append({"date": d.isoformat(), "revenue": rev, "appointments": appts})
        monthly_total += rev
        if rev > best_rev:
            best_rev = rev
            best_day = d.isoformat()
    weekly_avg = round(monthly_total / 4.3)
    return {
        "daily": daily,
        "weekly_avg": weekly_avg,
        "monthly_total": monthly_total,
        "best_day": best_day,
        "best_day_revenue": best_rev,
    }

