async def get_client_retention_cohort():
    import random
    random.seed(73)
    cohort_months = ["Nov '25", "Dec '25", "Jan '26", "Feb '26", "Mar '26", "Apr '26"]
    cohorts = []
    for i, cohort in enumerate(cohort_months):
        base = random.randint(52, 80)
        months = []
        val = 100
        for m in range(4):
            if m == 0:
                months.append(100)
            else:
                drop = random.randint(8, 22)
                val = max(val - drop, 20)
                months.append(val)
        cohort_size = random.randint(28, 65)
        cohorts.append({"cohort": cohort, "size": cohort_size, "retention": months})
    all_vals = [v for c in cohorts for v in c["retention"] if v < 100]
    avg_retention = round(sum(all_vals) / len(all_vals)) if all_vals else 0
    return {"cohorts": cohorts, "avg_retention": avg_retention, "months_label": ["Month 0", "Month 1", "Month 2", "Month 3"]}

