@app.get("/api/analytics/seasonal-trends")
async def get_seasonal_trends():
    import random
    random.seed(127)
    months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"]
    seasonal_base = [72, 68, 85, 95, 105, 130, 145, 138, 112, 98, 118, 152]
    data = []
    for i, m in enumerate(months):
        rev = seasonal_base[i] * 10 + random.randint(-150, 150)
        data.append({"month": m, "revenue": rev})
    avg = round(sum(d["revenue"] for d in data) / len(data))
    peak = max(data, key=lambda x: x["revenue"])
    return {"months": data, "avg_revenue": avg, "peak_month": peak["month"], "peak_revenue": peak["revenue"]}

