@app.get("/api/analytics/client-spend-distribution")
async def get_client_spend_distribution():
    import random
    random.seed(131)
    buckets = [
        {"label": "< $50",      "min": 0,   "max": 50,   "count": random.randint(38, 55)},
        {"label": "$50–$100",   "min": 50,  "max": 100,  "count": random.randint(95, 130)},
        {"label": "$100–$200",  "min": 100, "max": 200,  "count": random.randint(70, 95)},
        {"label": "$200–$500",  "min": 200, "max": 500,  "count": random.randint(30, 50)},
        {"label": "$500+",      "min": 500, "max": 9999, "count": random.randint(8, 18)},
    ]
    total = sum(b["count"] for b in buckets)
    for b in buckets:
        b["pct"] = round(b["count"] / total * 100, 1)
    # Weighted median estimate: $50-100 bucket dominates → median ~$85
    median_spend = 85
    return {"buckets": buckets, "total_clients": total, "median_spend": median_spend}

