@app.get("/api/analytics/churn-prediction")
async def get_churn_prediction():
    import random
    random.seed(137)
    names = ["Sandra M.","Dre Washington","Kim Patel","Tony B.","Aaliyah R.","Jerome F.",
             "Melissa C.","Hakeem O.","Bianca T.","Darius N.","Simone P.","Remy L."]
