@app.get("/api/analytics/service-duration-accuracy")
async def get_service_duration_accuracy():
    import random
    random.seed(139)
    services = [
        {"service": "Fade Haircut",       "scheduled": 30},
        {"service": "Beard Trim",          "scheduled": 20},
        {"service": "Full Color",          "scheduled": 90},
        {"service": "Blowout",             "scheduled": 45},
        {"service": "Hot Towel Shave",     "scheduled": 25},
        {"service": "Manicure",            "scheduled": 40},
        {"service": "Pedicure",            "scheduled": 50},
        {"service": "Highlights",          "scheduled": 120},
    ]
    result = []
    for s in services:
        delta = random.randint(-8, 15)
        actual = s["scheduled"] + delta
        accuracy = round(100 - abs(delta) / s["scheduled"] * 100, 1)
        result.append({
            "service": s["service"],
            "scheduled_min": s["scheduled"],
            "actual_avg_min": actual,
            "delta_min": delta,
            "accuracy_pct": max(accuracy, 0),
        })
    overall_accuracy = round(sum(r["accuracy_pct"] for r in result) / len(result), 1)
    return {"services": result, "overall_accuracy": overall_accuracy}

