@app.get("/api/analytics/walk-in-vs-booked")
async def get_walk_in_vs_booked():
    import random
    from datetime import datetime, timedelta
    random.seed(157)
    base = datetime.now()
    days = []
    for i in range(13, -1, -1):
        d = base - timedelta(days=i)
        is_weekend = d.weekday() >= 5
        walk_ins = random.randint(8, 22) if is_weekend else random.randint(3, 12)
        booked   = random.randint(18, 38) if is_weekend else random.randint(10, 25)
        days.append({
            "date": d.strftime("%m/%d"),
            "walk_ins": walk_ins,
            "booked": booked,
        })
    total_wi = sum(d["walk_ins"] for d in days)
    total_bk = sum(d["booked"] for d in days)
    total    = total_wi + total_bk
    return {
        "days": days,
        "walk_in_pct": round(total_wi / total * 100),
        "booked_pct":  round(total_bk / total * 100),
        "total_walk_ins": total_wi,
        "total_booked": total_bk,
    }

@app.get("/analytics/walk-in-vs-booked", response_class=HTMLResponse)
async def walk_in_vs_booked_page():
    return FileResponse("walk_in_vs_booked.html")

