@app.get("/api/analytics/ai-vs-human-booking")
async def get_ai_vs_human_booking():
    import random
    random.seed(163)
    weeks = ["W1","W2","W3","W4","W5","W6","W7","W8"]
    trend = []
    ai_share = 42.0
    for w in weeks:
        ai_share = min(85, max(30, ai_share + random.uniform(-2, 5)))
        total = random.randint(55, 95)
        ai_cnt    = round(total * ai_share / 100)
        human_cnt = total - ai_cnt
        trend.append({"week": w, "ai": ai_cnt, "human": human_cnt, "total": total})
    latest = trend[-1]
    ai_pct = round(latest["ai"] / latest["total"] * 100)
    return {
        "trend": trend,
        "current_ai_pct": ai_pct,
        "this_week_ai": latest["ai"],
        "this_week_human": latest["human"],
    }

