@app.get("/api/analytics/revenue-by-day-of-week")
async def get_revenue_by_day_of_week():
    import random
    random.seed(167)
    days = [
        {"day": "Monday",    "short": "Mon"},
        {"day": "Tuesday",   "short": "Tue"},
        {"day": "Wednesday", "short": "Wed"},
        {"day": "Thursday",  "short": "Thu"},
        {"day": "Friday",    "short": "Fri"},
        {"day": "Saturday",  "short": "Sat"},
        {"day": "Sunday",    "short": "Sun"},
    ]
    base = [310, 340, 360, 390, 480, 620, 220]
    data = []
    for i, d in enumerate(days):
        rev = base[i] + random.randint(-40, 60)
        data.append({"day": d["day"], "short": d["short"], "revenue": rev})
    best  = max(data, key=lambda x: x["revenue"])
    worst = min(data, key=lambda x: x["revenue"])
    return {"days": data, "best_day": best["day"], "best_revenue": best["revenue"],
            "worst_day": worst["day"], "worst_revenue": worst["revenue"]}

