@app.get("/api/analytics/avg-wait-time")
async def get_avg_wait_time():
    import random
    random.seed(173)
    hours = list(range(8, 19))  # 8am to 6pm
    data = []
    overall_sum = 0
    for h in hours:
        if h in (12, 13, 17, 18):
            base = 22
        elif h in (10, 11, 16):
            base = 15
        else:
            base = 8
        wait = base + random.randint(-3, 8)
        data.append({"hour": h, "wait_min": wait})
        overall_sum += wait
    overall_avg = round(overall_sum / len(data), 1)
    peak = max(data, key=lambda x: x["wait_min"])
    return {"hours": data, "overall_avg_min": overall_avg,
            "peak_hour": peak["hour"], "peak_wait_min": peak["wait_min"]}

@app.get("/analytics/avg-wait-time", response_class=HTMLResponse)
async def avg_wait_time_page():
    return FileResponse("avg_wait_time.html")

