@app.get("/api/analytics/peak-hours-heatmap")
async def get_peak_hours_heatmap():
    import random as _r
    _r.seed(223)
    days = ["Monday","Tuesday","Wednesday","Thursday","Friday","Saturday","Sunday"]
    hours = list(range(8, 21))
    heatmap = []
    for day in days:
        is_weekend = day in ("Saturday", "Sunday")
        hrs = []
        for h in hours:
            base = 60 if is_weekend else 40
            if h in (10, 11, 12, 13):
                base += 25 if not is_weekend else 30
            elif h in (17, 18, 19):
                base += 20 if not is_weekend else 15
            intensity = min(100, max(0, base + _r.randint(-20, 20)))
            hrs.append({"hour": h, "label": f"{h if h <= 12 else h-12}{'am' if h < 12 else 'pm'}", "intensity": intensity})
        heatmap.append({"day": day, "short": day[:3], "hours": hrs})
    return {"heatmap": heatmap}

