@app.get("/api/analytics/call-answer-rate")
async def get_call_answer_rate():
    import random as _r
    _r.seed(317)
    today = _dt.date.today()
    trend = []
    for i in range(8):
        w = today - _dt.timedelta(weeks=7 - i)
        total = _r.randint(120, 200)
        missed = _r.randint(int(total * 0.05), int(total * 0.14))
        answered = total - missed
        trend.append({"week": w.strftime("W%U"), "date": w.isoformat(), "answered": answered, "missed": missed, "total": total, "rate_pct": round(answered / total * 100, 1)})
    grand_total = sum(t["total"] for t in trend)
    grand_ans   = sum(t["answered"] for t in trend)
    return {"answer_rate_pct": round(grand_ans / grand_total * 100, 1), "missed_pct": round((grand_total - grand_ans) / grand_total * 100, 1), "total_calls": grand_total, "trend": trend}

