@app.get("/api/analytics/weekly-booking-volume")
async def weekly_booking_volume():
    import random as _r
    _r.seed(367)
    weeks = [f"Wk{i+1}" for i in range(12)]
    trend = []
    base = 95
    for w in weeks:
        total = base + _r.randint(-12, 18)
        completed = int(total * _r.uniform(0.82, 0.94))
        cancelled = total - completed - _r.randint(0, 5)
        trend.append({"week": w, "total": total, "completed": completed, "cancelled": max(0, cancelled)})
        base = total
    peak = max(trend, key=lambda x: x["total"])
    return {"trend": trend, "peak_week": peak["week"], "peak_total": peak["total"], "avg_total": round(sum(t["total"] for t in trend)/len(trend), 1)}

