@app.get("/api/analytics/hourly-call-volume")
async def hourly_call_volume():
    import random as _r
    _r.seed(397)
    hours_data = []
    labels = ["12a","1a","2a","3a","4a","5a","6a","7a","8a","9a","10a","11a",
              "12p","1p","2p","3p","4p","5p","6p","7p","8p","9p","10p","11p"]
    # Barbershop pattern: low overnight, ramp 8-10am, peak 11am-7pm, taper
    base_pattern = [0,0,0,0,0,1,2,5,12,22,38,45,48,50,52,49,47,44,40,32,18,10,5,2]
    for i, (lbl, base) in enumerate(zip(labels, base_pattern)):
        calls = max(0, base + _r.randint(-3, 4)) if base > 0 else 0
        hours_data.append({"hour": i, "label": lbl, "calls": calls})
    peak = max(hours_data, key=lambda x: x["calls"])
    return {"hours": hours_data, "peak_hour_label": peak["label"], "peak_calls": peak["calls"]}

