@app.get("/api/analytics/revenue-growth-rate")
async def revenue_growth_rate():
    import random as _r
    _r.seed(443)
    months = ["Sep","Oct","Nov","Dec","Jan","Feb","Mar","Apr"]
    revenues = []
    base = 4800
    for m in months:
        base = base * _r.uniform(1.04, 1.18)
        revenues.append(round(base, 2))
    result = []
    for i, (m, rev) in enumerate(zip(months, revenues)):
        growth = round((rev - revenues[i-1]) / revenues[i-1] * 100, 1) if i > 0 else None
        result.append({"month": m, "revenue": rev, "growth_pct": growth})
    avg_growth = round(sum(r["growth_pct"] for r in result if r["growth_pct"] is not None) / (len(result)-1), 1)
    return {"months": result, "avg_growth_pct": avg_growth}

@app.get("/analytics/revenue-growth-rate", response_class=HTMLResponse)
async def revenue_growth_rate_page():
    return FileResponse("revenue_growth_rate.html")

