@app.get("/api/analytics/daily-revenue-heatmap")
async def get_daily_revenue_heatmap():
    import random as _r
    _r.seed(457)
    days = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
    weeks = ["Week 1", "Week 2", "Week 3", "Week 4"]
    grid = []
    for w in weeks:
        row = []
        for d in days:
            base = 800 if d in ("Fri","Sat") else (300 if d == "Sun" else 550)
            row.append(round(base + _r.uniform(-150, 250)))
        grid.append({"week": w, "days": row})
    flat = [v for row in grid for v in row["days"]]
    return {"days": days, "weeks": weeks, "grid": grid, "max_revenue": max(flat), "min_revenue": min(flat)}

