@app.get("/api/analytics/no-show-rate-by-day")
async def get_no_show_rate_by_day():
    import random as _r
    _r.seed(479)
    days = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"]
    data = []
    for day in days:
        base = 12 if day == "Sunday" else (8 if day == "Monday" else 4)
        pct = round(base + _r.uniform(-2, 4), 1)
        data.append({"day": day, "no_show_pct": max(0.5, pct)})
    worst = max(data, key=lambda x: x["no_show_pct"])
    avg = round(sum(d["no_show_pct"] for d in data) / len(data), 1)
    return {"days": data, "worst_day": worst["day"], "avg_no_show_pct": avg}

