@app.get("/api/analytics/revenue-by-hour-of-week")
async def get_revenue_by_hour_of_week():
    import random as _r
    _r.seed(547)
    days = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
    hours = ["8am","9am","10am","11am","12pm","1pm","2pm","3pm","4pm","5pm","6pm","7pm"]
    grid = []
    for d in days:
        row = []
        for h in hours:
            is_weekend = d in ("Sat","Sun")
            is_peak = h in ("10am","11am","12pm","2pm","3pm")
            base = 180 if is_weekend else (140 if is_peak else 60)
            row.append(round(base + _r.uniform(-30, 60), 2))
        grid.append({"day": d, "hours": row})
    flat = [v for row in grid for v in row["hours"]]
    return {"days": days, "hours": hours, "grid": grid,
            "max_revenue": max(flat), "min_revenue": min(flat)}

@app.get("/analytics/revenue-by-hour-of-week", response_class=HTMLResponse)
async def revenue_by_hour_of_week_page():
    return FileResponse("revenue_by_hour_of_week.html")

