    _r.seed(631)
    names = ["Jordan Lee", "Priya Patel", "Marcus Webb", "Destiny Cruz", "Tomás Rivera", "Aisha Johnson"]
    services = ["Fade", "Color & Style", "Beard Trim", "Braids", "Haircut", "Full Color"]
    clients = []
    for i, name in enumerate(names):
        prob = round(_r.uniform(38, 94), 1)
        days = _r.randint(22, 68)
        clients.append({
            "name": name,
            "days_since_last_visit": days,
            "predicted_churn_probability": prob,
            "last_service": services[i]
        })
    clients.sort(key=lambda x: x["predicted_churn_probability"], reverse=True)
    return {"clients": clients, "high_risk_count": sum(1 for c in clients if c["predicted_churn_probability"] >= 70)}

