@app.get("/api/analytics/revenue-trend-yoy")
async def get_revenue_trend_yoy():
    import random as _r
    _r.seed(661)
    months = ["Nov", "Dec", "Jan", "Feb", "Mar", "Apr"]
    result = []
    for m in months:
        prior = round(_r.uniform(8000, 16000), 0)
        current = round(prior * _r.uniform(1.04, 1.28), 0)
        result.append({"month": m, "current_year": current, "prior_year": prior})
    total_current = sum(r["current_year"] for r in result)
    total_prior = sum(r["prior_year"] for r in result)
    growth_pct = round((total_current - total_prior) / total_prior * 100, 1)
    return {"months": result, "total_current": total_current, "total_prior": total_prior, "yoy_growth_pct": growth_pct}

