@app.get("/api/analytics/staff-schedule-gaps")
async def get_staff_schedule_gaps():
    import random as _r
    _r.seed(697)
    staff_names = ["Marcus", "Destiny", "Jayla", "Terrell"]
    days_of_week = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday"]
    hour_slots = ["9:00–10:00", "10:00–11:00", "11:00–12:00", "1:00–2:00", "2:00–3:00", "3:00–4:00", "4:00–5:00"]
    staff_gaps = []
    for name in staff_names:
        gaps = []
        used = set()
        while len(gaps) < 3:
            day = _r.choice(days_of_week)
            slot = _r.choice(hour_slots)
            key = (day, slot)
            if key not in used:
                used.add(key)
                gaps.append({"day": day, "slot": slot, "utilization_pct": _r.randint(5, 35)})
        staff_gaps.append({"staff": name, "gaps": gaps})
    return {"staff_gaps": staff_gaps}

@app.get("/analytics/staff-schedule-gaps", response_class=HTMLResponse)
async def staff_schedule_gaps_page():
    return FileResponse("staff_schedule_gaps.html")

