@app.get("/api/analytics/rebooking-interval")
async def get_rebooking_interval():
    import random
    random.seed(849)
    services = [
        {"service": "Haircut", "avg_days": 21, "median_days": 18},
        {"service": "Beard Trim", "avg_days": 14, "median_days": 12},
        {"service": "Color Treatment", "avg_days": 42, "median_days": 38},
        {"service": "Full Shave", "avg_days": 28, "median_days": 25},
        {"service": "Nail Service", "avg_days": 21, "median_days": 19},
        {"service": "Eyebrow Wax", "avg_days": 28, "median_days": 26},
    ]
    for s in services:
        s["avg_days"] += random.randint(-2, 3)
