@app.get("/api/analytics/hourly-revenue-heatmap")
async def get_hourly_revenue_heatmap():
    import random
    random.seed(853)
    days = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
    hours = ["9am", "10am", "11am", "12pm", "1pm", "2pm", "3pm", "4pm", "5pm", "6pm"]
    cells = []
    for day in days:
        for hour in hours:
            base = 80 if day in ["Fri", "Sat"] else 50
            if hour in ["11am", "12pm", "1pm"]:
                base += 30
            elif hour in ["9am", "6pm"]:
                base -= 20
            cells.append({
                "day": day,
                "hour": hour,
                "revenue_cents": max(0, base * 100 + random.randint(-2000, 2000))
            })
    return {"cells": cells, "days": days, "hours": hours}

