@app.get("/api/analytics/service-timing-variance")
async def api_service_timing_variance():
    import random; random.seed(941)
    services = ["Haircut","Color Treatment","Beard Trim","Highlights","Blowout"]
    result = []
    for svc in services:
        booked = random.choice([30, 45, 60, 75, 90])
        delta = random.randint(-10, 20)
        actual = booked + delta
        accuracy = round(max(0, 100 - abs(delta) / booked * 100), 1)
        result.append({"service_name": svc, "booked_minutes": booked, "actual_minutes": actual, "accuracy_pct": accuracy})
    return {"services": result}

@app.get("/analytics/service-timing-variance", response_class=HTMLResponse)
async def service_timing_variance_page():
    return FileResponse("service_duration_accuracy.html")

