@app.get("/api/analytics/staff-performance-ranking")
async def api_staff_performance_ranking():
    import random; random.seed(953)
    names = ["Alex","Jordan","Morgan","Taylor","Casey"]
    staff = []
    for n in names:
        appts = random.randint(48, 130)
        revenue = appts * random.randint(42, 78)
        rating = round(random.uniform(3.6, 5.0), 1)
        no_show = round(random.uniform(3.0, 18.0), 1)
        staff.append({"name": n, "appointments_completed": appts, "revenue_generated": revenue, "avg_rating": rating, "no_show_rate_pct": no_show})
    staff.sort(key=lambda x: x["revenue_generated"], reverse=True)
    return {"staff": staff}

