@app.get("/api/analytics/review-response-rate")  # seed 1053
async def get_review_response_rate():
    import random; rng = random.Random(1053)
    platforms = ["Google", "Yelp", "Facebook", "Booksy"]
    breakdown = [{"platform": p, "reviews": rng.randint(20, 120), "responded": rng.randint(10, 100)} for p in platforms]
    for b in breakdown:
        b["responded"] = min(b["responded"], b["reviews"])
        b["rate_pct"] = round(b["responded"] / b["reviews"] * 100)
    total_reviews = sum(b["reviews"] for b in breakdown)
    total_responded = sum(b["responded"] for b in breakdown)
    return {"total_reviews": total_reviews, "total_responded": total_responded, "overall_rate_pct": round(total_responded/total_reviews*100), "avg_response_time_hours": rng.randint(2, 24), "breakdown": breakdown}

