@app.get("/api/analytics/hourly-traffic-heatmap")  # seed 1055; sub for peak-hours-heatmap
async def get_hourly_traffic_heatmap():
    import random; rng = random.Random(1055)
    days = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
    hours = [f"{h}{'am' if h < 12 else 'pm'}" for h in range(8, 19)]
    matrix = {d: [rng.randint(0, 15) for _ in hours] for d in days}
    peak_day = max(days, key=lambda d: sum(matrix[d]))
    peak_hour = hours[max(range(len(hours)), key=lambda i: sum(matrix[d][i] for d in days))]
    return {"days": days, "hours": hours, "matrix": matrix, "peak_day": peak_day, "peak_hour": peak_hour, "total_weekly_calls": sum(sum(matrix[d]) for d in days)}

