async def get_client_retention_rate():
    import random; rng = random.Random(1057)
    months = ["Nov", "Dec", "Jan", "Feb", "Mar", "Apr"]
    rates = [round(rng.uniform(52, 78), 1) for _ in months]
    cohorts = [{"cohort": m, "started": rng.randint(18, 55), "retained_30d": rng.randint(12, 45), "retained_90d": rng.randint(8, 30)} for m in months[-3:]]
    for c in cohorts:
        c["retained_30d"] = min(c["retained_30d"], c["started"])
        c["retained_90d"] = min(c["retained_90d"], c["retained_30d"])
        c["rate_30d"] = round(c["retained_30d"] / c["started"] * 100)
        c["rate_90d"] = round(c["retained_90d"] / c["started"] * 100)
    return {"months": months, "retention_rates": rates, "current_retention_pct": rates[-1], "avg_retention_pct": round(sum(rates)/len(rates), 1), "best_month": months[rates.index(max(rates))], "cohort_analysis": cohorts}

