@app.get("/api/analytics/booking-lead-time")  # seed 1059
async def get_booking_lead_time():
    import random; rng = random.Random(1059)
    buckets = ["Same day", "1 day", "2–3 days", "4–7 days", "1–2 weeks", "2+ weeks"]
    counts = [rng.randint(5, 60) for _ in buckets]
    total = sum(counts)
    breakdown = [{"bucket": b, "count": c, "pct": round(c/total*100)} for b, c in zip(buckets, counts)]
    avg_days = round(sum(i*counts[i] for i in range(len(counts))) / total, 1)
    return {"buckets": buckets, "counts": counts, "breakdown": breakdown, "avg_lead_time_days": avg_days, "same_day_pct": breakdown[0]["pct"], "total_bookings_analyzed": total}

