@app.get("/api/analytics/appointment-duration-accuracy")  # seed 1067
async def get_appointment_duration_accuracy():
    import random; rng = random.Random(1067)
    services = ["Haircut", "Color", "Blowout", "Beard Trim", "Highlights", "Keratin"]
    breakdown = []
    for svc in services:
        booked = rng.randint(30, 120)
        actual = booked + rng.randint(-10, 20)
        breakdown.append({"service": svc, "booked_min": booked, "actual_min": actual, "variance_min": actual - booked, "accuracy_pct": max(0, round(100 - abs(actual-booked)/booked*100))})
    overall_accuracy = round(sum(b["accuracy_pct"] for b in breakdown) / len(breakdown))
    return {"services": services, "breakdown": breakdown, "overall_accuracy_pct": overall_accuracy, "avg_overrun_min": round(sum(max(0, b["variance_min"]) for b in breakdown) / len(breakdown), 1), "most_accurate_service": max(breakdown, key=lambda b: b["accuracy_pct"])["service"]}

