async def get_service_mix_breakdown():
    import random; rng = random.Random(1071)
    services = [
        {"service": "Haircut", "bookings": rng.randint(60, 180), "revenue": rng.randint(3000, 9000)},
        {"service": "Color", "bookings": rng.randint(20, 80), "revenue": rng.randint(2000, 8000)},
        {"service": "Beard Trim", "bookings": rng.randint(30, 100), "revenue": rng.randint(900, 3000)},
        {"service": "Blowout", "bookings": rng.randint(15, 60), "revenue": rng.randint(900, 3600)},
        {"service": "Highlights", "bookings": rng.randint(10, 40), "revenue": rng.randint(1500, 6000)},
        {"service": "Keratin", "bookings": rng.randint(5, 20), "revenue": rng.randint(1000, 4000)},
    ]
    total_bookings = sum(s["bookings"] for s in services)
    total_revenue = sum(s["revenue"] for s in services)
    for s in services:
        s["booking_pct"] = round(s["bookings"] / total_bookings * 100)
        s["revenue_pct"] = round(s["revenue"] / total_revenue * 100)
        s["avg_ticket"] = round(s["revenue"] / s["bookings"])
    top_revenue = max(services, key=lambda s: s["revenue"])["service"]
    return {"services": services, "total_bookings": total_bookings, "total_revenue": total_revenue, "top_revenue_service": top_revenue, "service_count": len(services)}

