@app.get("/api/analytics/peak-hour-utilization")
async def get_peak_hour_utilization():
    import random; rng = random.Random(1119)
    days = ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"]
    hours = ["8am","9am","10am","11am","12pm","1pm","2pm","3pm","4pm","5pm","6pm","7pm"]
    grid = []
    for d in days:
        row = []
        for h in hours:
            is_weekend = d in ("Sat","Sun")
            is_peak = h in ("10am","11am","12pm","1pm","2pm","3pm","4pm","5pm")
            base = 65 if is_peak else 30
            if is_weekend: base += 15
            row.append(min(100, round(rng.uniform(base-15, base+20))))
        grid.append(row)
    return {"days": days, "hours": hours, "grid": grid, "peak_day": "Saturday", "peak_hour": "11am", "overall_utilization": round(rng.uniform(58,72),1)}

