@app.get("/api/analytics/monthly-revenue-momentum")
async def get_monthly_revenue_momentum():
    import random; rng = random.Random(1125)
    months = ["May","Jun","Jul","Aug","Sep","Oct","Nov","Dec","Jan","Feb","Mar","Apr"]
    revenue = [round(rng.uniform(8200,18400),0) for _ in months]
    mom = round((revenue[-1]-revenue[-2])/max(revenue[-2],1)*100,1)
    yoy = round((revenue[-1]-revenue[0])/max(revenue[0],1)*100,1)
    projected = round(revenue[-1]*(1+rng.uniform(0.02,0.08)),0)
    mom_changes = [None]+[round((revenue[i]-revenue[i-1])/max(revenue[i-1],1)*100,1) for i in range(1,len(revenue))]
