@app.get("/api/analytics/stylist-performance-score")
async def get_stylist_performance_score():
    import random; rng = random.Random(1129)
    names = [("Jordan M.","JM"),("Taylor R.","TR"),("Alex K.","AK"),("Devon W.","DW"),("Morgan S.","MS")]
    stylists = []
    for name,init in names:
        fill = round(rng.uniform(58,95),1)
        rebook = round(rng.uniform(42,82),1)
        ticket = round(rng.uniform(38,95),2)
        noshow = round(rng.uniform(4,18),1)
        review = round(rng.uniform(3.8,5.0),1)
        score = round((fill*0.25 + rebook*0.25 + min(ticket/95*100,100)*0.2 + (100-noshow*4)*0.15 + review/5*100*0.15),1)
        stylists.append({"name":name,"initials":init,"score":score,"fill_rate":fill,"rebook_rate":rebook,"avg_ticket":ticket,"noshow_rate":noshow,"review_score":review})
    stylists.sort(key=lambda x:x["score"],reverse=True)
    prev_scores = [round(s["score"]-rng.uniform(-8,8),1) for s in stylists]
    most_improved = stylists[max(range(len(stylists)),key=lambda i:stylists[i]["score"]-prev_scores[i])]["name"]
    avg_score = round(sum(s["score"] for s in stylists)/len(stylists),1)
    return {"stylists":stylists,"top_performer":stylists[0]["name"],"avg_team_score":avg_score,"most_improved":most_improved}

@app.get("/analytics/stylist-performance-score", response_class=HTMLResponse)
async def stylist_performance_score_page():
    return FileResponse("stylist_performance_analytics.html")

