    advance_7plus_pct = round(rng.uniform(18, 38), 1)
    total = 100
    b1 = same_day_pct
    b5 = advance_7plus_pct
    rem = round(total - b1 - b5, 1)
    b2 = round(rem * rng.uniform(0.28, 0.36), 1)
    b3 = round(rem * rng.uniform(0.30, 0.38), 1)
    b4 = round(rem - b2 - b3, 1)
    lead_time_buckets = [
        {"label": "Same Day", "pct": b1},
        {"label": "1 Day", "pct": b2},
        {"label": "2–3 Days", "pct": b3},
        {"label": "4–7 Days", "pct": b4},
        {"label": "8+ Days", "pct": b5},
    ]
    return {"avg_lead_time_hours": avg_lead_time_hours, "same_day_pct": same_day_pct, "advance_7plus_pct": advance_7plus_pct, "months": months, "monthly_avg_lead": monthly_avg_lead, "lead_time_buckets": lead_time_buckets}

