async def get_missed_call_recovery():
    import random; rng = random.Random(1149)
    months = ["Nov","Dec","Jan","Feb","Mar","Apr"]
    monthly_missed = [rng.randint(18, 55) for _ in months]
    total_missed = sum(monthly_missed)
    recovered_pct = round(rng.uniform(52, 78), 1)
    revenue_recovered_est = round(rng.uniform(800, 2800), 0)
    avg_callback_minutes = round(rng.uniform(4, 18), 1)
    recovered = int(total_missed * recovered_pct / 100)
    ai_cb = int(recovered * rng.uniform(0.35, 0.45))
    sms_fu = int(recovered * rng.uniform(0.25, 0.32))
    client_cb = recovered - ai_cb - sms_fu
    unrecovered = total_missed - recovered
    recovery_breakdown = [
        {"method": "AI Callback", "count": ai_cb, "pct": round(ai_cb / total_missed * 100, 1)},
        {"method": "SMS Follow-up", "count": sms_fu, "pct": round(sms_fu / total_missed * 100, 1)},
        {"method": "Client Called Back", "count": client_cb, "pct": round(client_cb / total_missed * 100, 1)},
        {"method": "Unrecovered", "count": unrecovered, "pct": round(unrecovered / total_missed * 100, 1)},
    ]
    return {"total_missed": total_missed, "recovered_pct": recovered_pct, "revenue_recovered_est": revenue_recovered_est, "avg_callback_minutes": avg_callback_minutes, "months": months, "monthly_missed": monthly_missed, "recovery_breakdown": recovery_breakdown}

