@app.get("/api/analytics/call-peak-distribution")  # seed 1153; sub for peak-hour-heatmap (collision)
async def get_call_peak_distribution():
    import random; rng = random.Random(1153)
    days = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"]
    grid = []
    for d in range(7):
        row = []
        for h in range(24):
            if h < 8 or h > 21:
                row.append(0)
            else:
                base = rng.uniform(0, 1)
                if d in (5, 6) and 10 <= h <= 17: base *= 2.2
                if d in (1, 2) and 9 <= h <= 12: base *= 1.5
                row.append(round(base, 3))
        grid.append(row)
    flat = [v for row in grid for v in row]
    max_val = max(flat) or 1
    peak_idx = flat.index(max(flat))
    peak_day = days[peak_idx // 24]
    peak_hour_num = peak_idx % 24
    ampm = "AM" if peak_hour_num < 12 else "PM"
    h12 = peak_hour_num % 12 or 12
    top_hour = f"{peak_day} {h12}{ampm}"
    busiest_day = days[max(range(7), key=lambda d: sum(grid[d]))]
    total = sum(flat)
    avg_calls = round(total / (7 * 24), 2)
    return {"grid": grid, "days": days, "top_hour": top_hour, "busiest_day": busiest_day, "avg_calls_per_hour": avg_calls, "max_val": round(max_val, 3)}

