@app.get("/api/analytics/cancellation-rate-trend")  # seed 1157
async def get_cancellation_rate_trend():
    import random; rng = random.Random(1157)
    months = ["Nov","Dec","Jan","Feb","Mar","Apr"]
    monthly_cancel_rates = [round(rng.uniform(6, 22), 1) for _ in months]
    cancel_rate_pct = round(sum(monthly_cancel_rates) / len(monthly_cancel_rates), 1)
    revenue_lost_est = round(rng.uniform(400, 2200), 0)
    avg_notice_hours = round(rng.uniform(3, 30), 1)
    same_day_pct = round(rng.uniform(15, 40), 1)
    reasons = ["No reason given", "Scheduling conflict", "Illness", "Weather", "Changed mind", "Work emergency"]
    total_cancels = rng.randint(60, 140)
    raw = [rng.randint(5, 40) for _ in reasons]
    total_raw = sum(raw)
    by_reason = [{"reason": reasons[i], "count": int(raw[i]/total_raw*total_cancels), "pct": round(raw[i]/total_raw*100, 1)} for i in range(len(reasons))]
    by_reason.sort(key=lambda x: x["count"], reverse=True)
    return {"cancel_rate_pct": cancel_rate_pct, "revenue_lost_est": revenue_lost_est, "avg_notice_hours": avg_notice_hours, "same_day_pct": same_day_pct, "months": months, "monthly_cancel_rates": monthly_cancel_rates, "by_reason": by_reason}

