@app.get("/api/analytics/monthly-revenue-projection")  # seed 1163; sub for revenue-forecast (collision)
async def get_monthly_revenue_projection():
    import random; rng = random.Random(1163)
    base = rng.uniform(4200, 7800)
    current_month_est = round(base * rng.uniform(0.88, 1.05), 0)
    next_month_forecast = round(base * rng.uniform(1.05, 1.18), 0)
    three_month_forecast = round(base * rng.uniform(1.22, 1.45), 0)
    ytd_actual = round(base * rng.uniform(3.8, 4.5), 0)
    forecast_confidence_pct = round(rng.uniform(71, 89), 1)
    months_ahead = ["May","Jun","Jul","Aug","Sep","Oct"]
    monthly_forecast = []
    val = base
    for m in months_ahead:
        growth = rng.uniform(1.03, 1.12)
        val = val * growth
        spread = val * rng.uniform(0.08, 0.14)
        monthly_forecast.append({"month": m, "low": round(val - spread, 0), "mid": round(val, 0), "high": round(val + spread, 0)})
    return {"current_month_est": current_month_est, "next_month_forecast": next_month_forecast, "three_month_forecast": three_month_forecast, "ytd_actual": ytd_actual, "forecast_confidence_pct": forecast_confidence_pct, "monthly_forecast": monthly_forecast}

@app.get("/analytics/monthly-revenue-projection", response_class=HTMLResponse)
async def monthly_revenue_projection_page():
    return FileResponse("revenue_forecast_analytics.html")

