@app.get("/api/analytics/client-growth-rate")
async def get_client_growth_rate():
    import random; rng = random.Random(1181)
    months = ["Nov","Dec","Jan","Feb","Mar","Apr"]
    new_clients = [rng.randint(18,55) for _ in months]
    churned = [rng.randint(2,12) for _ in months]
    net = [new_clients[i] - churned[i] for i in range(len(months))]
    total = 180 + sum(net)
    return {"total_active_clients": total, "new_clients_this_month": new_clients[-1], "churn_this_month": churned[-1], "net_growth": net[-1], "growth_rate_pct": round((net[-1]/max(total-net[-1],1))*100,1), "months": months, "new_clients": new_clients, "churned": churned, "net_growth_series": net}

