async def get_upsell_offer_conversion():
    import random; rng = random.Random(1185)
    offers = [{"offer": "Beard Line-Up Add-On", "presented": rng.randint(80,200), "accepted": rng.randint(20,60), "revenue": rng.randint(300,900)},
              {"offer": "Scalp Treatment", "presented": rng.randint(60,150), "accepted": rng.randint(10,40), "revenue": rng.randint(200,700)},
              {"offer": "Deep Conditioning", "presented": rng.randint(40,100), "accepted": rng.randint(8,30), "revenue": rng.randint(150,500)},
              {"offer": "Hot Towel Shave", "presented": rng.randint(50,120), "accepted": rng.randint(12,35), "revenue": rng.randint(180,600)}]
    for o in offers: o["conversion_pct"] = round(o["accepted"]/max(o["presented"],1)*100,1)
    total_rev = sum(o["revenue"] for o in offers)
    return {"total_upsell_revenue": total_rev, "avg_conversion_pct": round(sum(o["conversion_pct"] for o in offers)/len(offers),1), "top_offer": offers[0]["offer"], "offers": offers}

