@app.get("/api/analytics/lead-time-histogram")
async def get_lead_time_histogram():
    import random; rng=random.Random(1209)
    buckets=["Same day","1 day","2-3 days","4-7 days","1-2 weeks","2+ weeks"]
    counts=[rng.randint(20,120) for _ in buckets]
    total=sum(counts)
    distribution=[{"bucket":b,"count":c,"pct":round(c/total*100,1)} for b,c in zip(buckets,counts)]
    same=distribution[0]["pct"]; nxt=distribution[1]["pct"]
    week_plus=round(sum(d["pct"] for d in distribution[3:]),1)
    avg=round(sum(i*c for i,c in enumerate([0,1,2.5,5.5,10,18]))/total*max(counts)*0.01+1.8,1)
    return {"avg_days":avg,"pct_same_day":same,"pct_next_day":nxt,"pct_week_plus":week_plus,"distribution":distribution}

