@app.get("/api/analytics/revenue-heatmap-data")
async def get_revenue_heatmap_data():
    import random; rng=random.Random(1211)
    days=["Mon","Tue","Wed","Thu","Fri","Sat","Sun"]
    hours=["8am","9am","10am","11am","12pm","1pm","2pm","3pm","4pm","5pm","6pm","7pm"]
    cells=[]
    peak_val=0; peak_hour=""; peak_day=""
    for d in days:
        for h in hours:
            base = rng.randint(0,180)
            is_weekend = d in ["Fri","Sat"]
            is_midday = h in ["11am","12pm","1pm","2pm"]
            rev = round(base * (1.4 if is_weekend else 1) * (1.3 if is_midday else 1) * rng.uniform(0.6,1.0), 2)
            cells.append({"day":d,"hour":h,"revenue":rev})
            if rev > peak_val: peak_val=rev; peak_hour=h; peak_day=d
    return {"peak_hour":peak_hour,"peak_day":peak_day,"cells":cells}

