@app.get("/api/analytics/staff-utilization-stats")
async def get_staff_utilization_stats():
    import random; rng = random.Random(1219)
    names = ["Marcus","Deja","Luis","Tanya","Kev"]
    colors = ["#a78bfa","#34d399","#60a5fa","#fbbf24","#f87171"]
    staff = []
    for name, color in zip(names, colors):
        avail = round(rng.uniform(32, 48), 1)
        util_pct = round(rng.uniform(52, 95), 1)
        booked = round(avail * util_pct / 100, 1)
        staff.append({"name": name, "utilization_pct": util_pct, "booked_hours": booked, "available_hours": avail, "color": color})
    avg_util = round(sum(s["utilization_pct"] for s in staff) / len(staff), 1)
    peak_util = max(s["utilization_pct"] for s in staff)
    return {"avg_utilization_pct": avg_util, "peak_utilization_pct": peak_util, "staff": staff}

