@app.get("/api/analytics/revenue-by-service-stats")
async def get_revenue_by_service_stats():
    import random; rng = random.Random(1221)
    services_raw = [
        ("Haircut", "#a78bfa"), ("Beard Trim", "#60a5fa"), ("Color", "#34d399"),
        ("Blowout", "#fbbf24"), ("Nails", "#f87171"), ("Facial", "#818cf8")
    ]
    services = []
    total = 0
    for name, color in services_raw:
        count = rng.randint(40, 220)
        avg_ticket = round(rng.uniform(28, 120), 2)
        revenue = round(count * avg_ticket, 2)
        total += revenue
        services.append({"name": name, "revenue": revenue, "count": count, "avg_ticket": avg_ticket, "color": color})
    total = round(total, 2)
    for s in services:
        s["pct"] = round(s["revenue"] / total * 100, 1)
    services.sort(key=lambda x: x["revenue"], reverse=True)
    top = services[0]["name"]
    return {"total_revenue": total, "top_service": top, "services": services}

