@app.get("/api/analytics/missed-call-recovery-stats")
async def get_missed_call_recovery_stats():
    import random; rng = random.Random(1227)
    total_missed = rng.randint(80, 160)
    recovered_count = rng.randint(40, int(total_missed * 0.75))
    recovered_pct = round(recovered_count / total_missed * 100, 1)
    revenue_recovered = round(recovered_count * rng.uniform(35, 75), 2)
    hours = list(range(8, 20))
    by_hour = [{"hour": h, "missed": rng.randint(2, 18), "recovered": rng.randint(1, 12)} for h in hours]
    methods = [
        {"method": "AI callback SMS", "count": rng.randint(20, 50), "pct": 0},
        {"method": "Voicemail + callback", "count": rng.randint(10, 30), "pct": 0},
        {"method": "Online booking link", "count": rng.randint(5, 20), "pct": 0},
        {"method": "Manual return call", "count": rng.randint(3, 15), "pct": 0}
    ]
    mtotal = sum(m["count"] for m in methods)
    for m in methods:
        m["pct"] = round(m["count"] / mtotal * 100, 1)
    return {"total_missed": total_missed, "recovered_pct": recovered_pct, "revenue_recovered": revenue_recovered, "by_hour": by_hour, "recovery_methods": methods}

