@app.get("/api/analytics/peak-hours-stats")
async def get_peak_hours_stats():
    import random; rng = random.Random(1251)
    hours = []
    for h in range(8, 20):
        label = f"{h if h <= 12 else h-12}{'am' if h < 12 else 'pm'}"
        base = 12 if 10 <= h <= 14 or h == 17 or h == 18 else 5
        calls = rng.randint(max(1, base-4), base+8)
        bookings = rng.randint(int(calls*0.4), int(calls*0.7))
        hours.append({"hour": label, "hour_int": h, "calls": calls, "bookings": bookings})
    peak = max(hours, key=lambda x: x["calls"])
    days = []
    for day in ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"]:
        base = 55 if day in ["Fri","Sat"] else 30 if day == "Sun" else 42
        days.append({"day": day, "calls": rng.randint(base-10, base+18), "bookings": rng.randint(int(base*0.4), int(base*0.65))})
    return {"peak_hour": peak["hour"], "peak_hour_calls": peak["calls"], "peak_day": "Saturday", "busiest_window": "10am–2pm", "hours": hours, "days": days}

