@app.get("/api/analytics/inbound-call-volume-stats")
async def get_inbound_call_volume_stats():
    import random; rng = random.Random(1269)
    months = ["Aug","Sep","Oct","Nov","Dec","Jan","Feb","Mar"]
    monthly = [{"month": m, "total_calls": rng.randint(280,520), "answered": 0, "missed": 0, "ai_handled": 0} for m in months]
    for m in monthly:
        m["missed"] = int(m["total_calls"] * rng.uniform(0.08, 0.18))
        m["answered"] = m["total_calls"] - m["missed"]
        m["ai_handled"] = int(m["answered"] * rng.uniform(0.74, 0.92))
    hours = []
    for h in range(8, 21):
        label = f"{h if h <= 12 else h-12}{'am' if h < 12 else 'pm'}"
        calls = rng.randint(8, 65)
        hours.append({"hour": label, "hour_int": h, "calls": calls})
    peak_h = max(hours, key=lambda x: x["calls"])
    last = monthly[-1]
    return {
        "total_calls_30d": last["total_calls"],
        "answered_30d": last["answered"],
        "missed_30d": last["missed"],
        "ai_handled_30d": last["ai_handled"],
        "ai_handle_rate_pct": round(last["ai_handled"] / last["answered"] * 100, 1) if last["answered"] else 0,
        "peak_hour": peak_h["hour"],
        "peak_hour_calls": peak_h["calls"],
        "monthly": monthly,
        "by_hour": hours,
    }
@app.get("/pages/inbound-call-volume-analytics")
async def page_inbound_call_volume(): return FileResponse("inbound_call_volume_analytics.html")

