@app.get("/api/analytics/service-revenue-stats")
async def get_service_revenue_stats():
    import random; rng = random.Random(1275)
    services = [
        {"service": "Manicure", "color": "#a78bfa"},
        {"service": "Pedicure", "color": "#34d399"},
        {"service": "Full Color", "color": "#fbbf24"},
        {"service": "Haircut", "color": "#f87171"},
        {"service": "Balayage", "color": "#60a5fa"},
        {"service": "Waxing", "color": "#fb923c"},
        {"service": "Facial", "color": "#e879f9"},
    ]
    months = ["Aug","Sep","Oct","Nov","Dec","Jan","Feb","Mar"]
    for s in services:
        s["revenue_30d"] = round(rng.uniform(800, 6200), 2)
        s["bookings_30d"] = rng.randint(18, 95)
        s["avg_ticket"] = round(s["revenue_30d"] / s["bookings_30d"], 2)
        s["revenue_prev_30d"] = round(s["revenue_30d"] * rng.uniform(0.82, 1.18), 2)
        s["growth_pct"] = round((s["revenue_30d"] - s["revenue_prev_30d"]) / s["revenue_prev_30d"] * 100, 1)
    total = round(sum(s["revenue_30d"] for s in services), 2)
    top = max(services, key=lambda x: x["revenue_30d"])
    monthly = [{"month": m, "total_revenue": round(rng.uniform(12000, 28000), 2)} for m in months]
    return {
        "total_revenue_30d": total,
        "top_service": top["service"],
        "top_service_revenue": top["revenue_30d"],
        "avg_ticket_all_services": round(total / sum(s["bookings_30d"] for s in services), 2),
        "services": services,
        "monthly": monthly,
    }
