@app.get("/api/analytics/client-growth-stats")
async def get_client_growth_stats():
    import random; rng = random.Random(1277)
    months = ["Aug","Sep","Oct","Nov","Dec","Jan","Feb","Mar"]
    monthly = []
    total = 480
    for m in months:
        new = rng.randint(18, 52)
        churned = rng.randint(4, 14)
        total = total + new - churned
        monthly.append({"month": m, "new_clients": new, "churned": churned, "total_clients": total, "net_growth": new - churned})
    last = monthly[-1]
    prev = monthly[-2]
    return {
        "total_clients": last["total_clients"],
        "new_clients_30d": last["new_clients"],
        "churned_30d": last["churned"],
        "net_growth_30d": last["net_growth"],
        "growth_rate_pct": round(last["net_growth"] / prev["total_clients"] * 100, 2),
        "avg_new_per_month": round(sum(m["new_clients"] for m in monthly) / len(monthly), 1),
        "best_growth_month": max(monthly, key=lambda x: x["net_growth"])["month"],
        "monthly": monthly,
    }
