@app.get("/api/analytics/monthly-revenue-stats")
async def get_monthly_revenue_stats():
    rng = _random193.Random(1319)
    months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"]
    base = rng.uniform(16000,20000)
    monthly = []
    for i,m in enumerate(months):
        rev = round(base * (1 + i*0.012 + rng.uniform(-0.04,0.06)), 2)
        monthly.append({
            "month": m,
            "revenue": rev,
            "services_revenue": round(rev * rng.uniform(0.72,0.82), 2),
            "retail_revenue": round(rev * rng.uniform(0.08,0.14), 2),
            "tips_revenue": round(rev * rng.uniform(0.08,0.12), 2),
            "transactions": rng.randint(290,380),
            "growth_pct": round(rng.uniform(-3,8),1),
        })
    return {
        "total_ytd": round(sum(m["revenue"] for m in monthly), 2),
        "best_month": max(monthly, key=lambda x: x["revenue"])["month"],
        "worst_month": min(monthly, key=lambda x: x["revenue"])["month"],
        "avg_monthly_revenue": round(sum(m["revenue"] for m in monthly)/len(monthly), 2),
        "yoy_growth_pct": round(rng.uniform(10,22),1),
        "monthly": monthly,
    }

