@app.get("/api/analytics/hourly-traffic-stats")
async def get_hourly_traffic_stats():
    rng = _random195.Random(1329)
    days = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
    hours = [f"{h}{'am' if h < 12 else 'pm'}" for h in list(range(9, 12)) + [12] + list(range(1, 8))]
    heatmap = []
    for day in days:
        for h_idx, hour in enumerate(hours):
            is_weekend = day in ["Sat", "Sun"]
            is_peak = (day in ["Fri", "Sat"] and h_idx in [2, 3, 4]) or (not is_weekend and h_idx in [1, 2])
            bookings = rng.randint(6, 18) if is_peak else rng.randint(0, 8)
            heatmap.append({"day": day, "hour": hour, "bookings": bookings})
    day_totals = []
    for day in days:
        total = sum(h["bookings"] for h in heatmap if h["day"] == day)
        day_totals.append({"day": day, "total": total})
    busiest = max(heatmap, key=lambda x: x["bookings"])
    return {
        "busiest_day": max(day_totals, key=lambda x: x["total"])["day"],
        "busiest_hour": busiest["hour"],
        "peak_combo": f"{busiest['day']} at {busiest['hour']}",
        "slowest_day": min(day_totals, key=lambda x: x["total"])["day"],
        "total_slots_analyzed": len(heatmap),
        "avg_bookings_per_slot": round(sum(h["bookings"] for h in heatmap) / len(heatmap), 1),
        "heatmap": heatmap,
        "day_totals": day_totals,
        "hours": hours,
        "days": days,
    }

