def _load_peak_hours_revenue_stats():
    rng = _random196.Random(1341)
    days = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
    slots = ["9am", "10am", "11am", "12pm", "1pm", "2pm", "3pm", "4pm", "5pm", "6pm", "7pm"]
    heatmap = []
    for d in days:
        for h in slots:
            base = rng.randint(80, 350)
            if d in ["Fri", "Sat"]: base = int(base * 1.4)
            if h in ["11am", "12pm", "1pm"]: base = int(base * 1.25)
            heatmap.append({"day": d, "slot": h, "revenue": round(base + rng.uniform(0, 50), 2)})
    day_totals = []
    for d in days:
        tot = sum(c["revenue"] for c in heatmap if c["day"] == d)
        day_totals.append({"day": d, "total": round(tot, 2)})
    slot_totals = []
    for h in slots:
        tot = sum(c["revenue"] for c in heatmap if c["slot"] == h)
        slot_totals.append({"slot": h, "total": round(tot, 2)})
    best_day = max(day_totals, key=lambda x: x["total"])["day"]
    best_slot = max(slot_totals, key=lambda x: x["total"])["slot"]
    worst_day = min(day_totals, key=lambda x: x["total"])["day"]
    total_revenue_30d = round(sum(c["revenue"] for c in heatmap) * 4.3, 2)
    avg_per_slot = round(sum(c["revenue"] for c in heatmap) / len(heatmap), 2)
    return {
        "best_day": best_day,
        "best_slot": best_slot,
        "worst_day": worst_day,
        "total_revenue_30d": total_revenue_30d,
        "avg_revenue_per_slot": avg_per_slot,
        "heatmap": heatmap,
        "day_totals": day_totals,
        "slot_totals": slot_totals,
        "days": days,
        "slots": slots,
    }

