def _load_staff_booking_stats():
    rng = _random196.Random(1347)
    staff_names = ["Jordan M.", "Taylor R.", "Casey L.", "Morgan P."]
    colors = ["#a78bfa", "#34d399", "#fbbf24", "#f87171"]
    staff = []
    for i, name in enumerate(staff_names):
        util = round(rng.uniform(62, 95), 1)
        bookings = rng.randint(40, 95)
        revenue = round(bookings * rng.uniform(55, 85), 2)
        no_show = round(rng.uniform(3, 14), 1)
        rebook = round(rng.uniform(45, 78), 1)
        avg_ticket = round(revenue / bookings, 2)
        staff.append({
            "name": name, "color": colors[i], "utilization_pct": util,
            "bookings_30d": bookings, "revenue_30d": revenue, "avg_ticket": avg_ticket,
            "no_show_rate_pct": no_show, "rebook_rate_pct": rebook,
        })
    monthly = []
    for i, m in enumerate(["Aug","Sep","Oct","Nov","Dec","Jan","Feb","Mar","Apr","May","Jun","Jul"]):
        monthly.append({
            "month": m,
            "total_bookings": rng.randint(160, 340),
            "total_revenue": round(rng.uniform(9000, 22000), 2),
        })
    top_staff = max(staff, key=lambda x: x["bookings_30d"])["name"]
    highest_ticket = max(staff, key=lambda x: x["avg_ticket"])["name"]
    avg_utilization = round(sum(s["utilization_pct"] for s in staff) / len(staff), 1)
    total_bookings_30d = sum(s["bookings_30d"] for s in staff)
    return {
        "top_staff_by_bookings": top_staff,
        "highest_avg_ticket": highest_ticket,
        "avg_team_utilization_pct": avg_utilization,
        "total_bookings_30d": total_bookings_30d,
        "staff": staff,
        "monthly": monthly,
    }

