def _load_no_show_stats():
    rng = _random197.Random(1361)
    months = ["Aug","Sep","Oct","Nov","Dec","Jan","Feb","Mar","Apr","May","Jun","Jul"]
    monthly = []
    for m in months:
        total = rng.randint(120, 280)
        ns = rng.randint(8, 32)
        monthly.append({
            "month": m,
            "total_appointments": total,
            "no_shows": ns,
            "no_show_rate_pct": round(ns / total * 100, 1),
            "recovered": rng.randint(1, max(1, ns // 2)),
        })
    days = ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"]
    by_day = [{"day": d, "no_show_rate_pct": round(rng.uniform(4, 18), 1)} for d in days]
    reasons = [
        {"reason": "Forgot appointment", "pct": round(rng.uniform(28, 38), 1), "color": "#a78bfa"},
        {"reason": "Emergency / illness", "pct": round(rng.uniform(18, 26), 1), "color": "#34d399"},
        {"reason": "No reminder received", "pct": round(rng.uniform(12, 20), 1), "color": "#fbbf24"},
        {"reason": "Schedule conflict", "pct": round(rng.uniform(10, 16), 1), "color": "#f87171"},
        {"reason": "Price concern", "pct": round(rng.uniform(5, 12), 1), "color": "#fb923c"},
        {"reason": "Other / unknown", "pct": round(rng.uniform(5, 10), 1), "color": "#666"},
    ]
    total_30d = rng.randint(18, 38)
    rate_30d = round(rng.uniform(7, 14), 1)
    recovered_30d = rng.randint(4, 12)
    fee_revenue_30d = round(recovered_30d * rng.uniform(20, 50), 2)
    return {
        "no_shows_30d": total_30d,
        "no_show_rate_pct": rate_30d,
        "recovered_30d": recovered_30d,
        "no_show_fee_revenue_30d": fee_revenue_30d,
        "worst_day": max(by_day, key=lambda x: x["no_show_rate_pct"])["day"],
        "monthly": monthly,
        "by_day": by_day,
        "reasons": reasons,
    }

