def _load_revenue_per_client_stats():
    rng = _random197.Random(1367)
    brackets = [
        {"label": "$0–$99", "count": rng.randint(20, 45), "color": "#666"},
        {"label": "$100–$249", "count": rng.randint(30, 60), "color": "#a78bfa"},
        {"label": "$250–$499", "count": rng.randint(25, 50), "color": "#34d399"},
        {"label": "$500–$999", "count": rng.randint(15, 35), "color": "#fbbf24"},
        {"label": "$1,000+", "count": rng.randint(8, 20), "color": "#f87171"},
    ]
    total_clients = sum(b["count"] for b in brackets)
    total_rev = sum(
        b["count"] * (
            [50, 175, 375, 750, 1400][i] + rng.uniform(-20, 20)
        ) for i, b in enumerate(brackets)
    )
    avg_rev = round(total_rev / total_clients, 2)
    median_rev = round(rng.uniform(180, 280), 2)
    top10_threshold = round(rng.uniform(700, 1100), 2)
    top_clients = []
    names = ["Marcus T.", "Jordan L.", "Taylor W.", "Casey M.", "Riley K.", "Avery S."]
    for i, name in enumerate(names):
        visits = rng.randint(8, 25)
        avg_ticket = round(rng.uniform(55, 95), 2)
        ltv = round(visits * avg_ticket, 2)
        top_clients.append({
            "name": name, "ltv_12m": ltv, "visits_12m": visits,
            "avg_ticket": avg_ticket, "last_visit_days_ago": rng.randint(2, 30),
        })
    top_clients.sort(key=lambda x: x["ltv_12m"], reverse=True)
    monthly = []
    for m in ["Aug","Sep","Oct","Nov","Dec","Jan","Feb","Mar","Apr","May","Jun","Jul"]:
        monthly.append({
            "month": m,
            "avg_revenue_per_client": round(rng.uniform(85, 160), 2),
            "active_clients": rng.randint(40, 90),
        })
    return {
        "avg_revenue_per_client_12m": avg_rev,
        "median_revenue_per_client": median_rev,
        "top_10pct_threshold": top10_threshold,
        "total_clients_analyzed": total_clients,
        "brackets": brackets,
        "top_clients": top_clients,
        "monthly": monthly,
    }

