def _load_client_visit_frequency_stats():
    rng = _random198.Random(1377)
    freq_buckets = [
        {"label": "Weekly", "count": rng.randint(8, 20), "color": "#a78bfa"},
        {"label": "Bi-weekly", "count": rng.randint(20, 45), "color": "#34d399"},
        {"label": "Monthly", "count": rng.randint(30, 65), "color": "#fbbf24"},
        {"label": "Every 6-8 wks", "count": rng.randint(20, 40), "color": "#fb923c"},
        {"label": "Quarterly+", "count": rng.randint(10, 28), "color": "#f87171"},
        {"label": "Once only", "count": rng.randint(15, 35), "color": "#666"},
    ]
    total = sum(b["count"] for b in freq_buckets)
    avg_days_between = round(rng.uniform(24, 38), 1)
    median_days_between = round(rng.uniform(28, 42), 1)
    most_common = max(freq_buckets, key=lambda x: x["count"])["label"]
    monthly = []
    for m in ["Aug","Sep","Oct","Nov","Dec","Jan","Feb","Mar","Apr","May","Jun","Jul"]:
        monthly.append({
            "month": m,
            "avg_days_between_visits": round(rng.uniform(22, 40), 1),
            "returning_clients": rng.randint(35, 85),
        })
    top_returning = []
    names = ["Jordan M.", "Casey L.", "Taylor R.", "Morgan P.", "Riley K."]
    for name in names:
        visits = rng.randint(18, 52)
        avg_gap = round(rng.uniform(7, 21), 1)
        top_returning.append({"name": name, "visits_12m": visits, "avg_days_between": avg_gap})
    top_returning.sort(key=lambda x: x["visits_12m"], reverse=True)
    return {
        "avg_days_between_visits": avg_days_between,
        "median_days_between_visits": median_days_between,
        "most_common_frequency": most_common,
        "total_returning_clients": total,
        "freq_buckets": freq_buckets,
        "monthly": monthly,
        "top_returning": top_returning,
    }

