def _load_walk_in_vs_booked_stats():
    rng = _random199.Random(1397)
    months = ["Aug","Sep","Oct","Nov","Dec","Jan","Feb","Mar","Apr","May","Jun","Jul"]
    monthly = []
    for m in months:
        booked = rng.randint(90, 200)
        walkin = rng.randint(15, 55)
        total = booked + walkin
        monthly.append({
            "month": m,
            "booked": booked,
            "walk_in": walkin,
            "total": total,
            "walk_in_pct": round(walkin / total * 100, 1),
        })
    days = ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"]
    by_day = []
    for d in days:
        walkin_pct = round(rng.uniform(10, 40), 1)
        by_day.append({"day": d, "walk_in_pct": walkin_pct, "booked_pct": round(100 - walkin_pct, 1)})
    total_30d = rng.randint(180, 350)
    walkin_30d = rng.randint(30, 80)
    booked_30d = total_30d - walkin_30d
    avg_walkin_ticket = round(rng.uniform(45, 65), 2)
    avg_booked_ticket = round(rng.uniform(65, 90), 2)
    peak_walkin_day = max(by_day, key=lambda x: x["walk_in_pct"])["day"]
    return {
        "total_appointments_30d": total_30d,
        "booked_30d": booked_30d,
        "walk_in_30d": walkin_30d,
        "walk_in_pct_30d": round(walkin_30d / total_30d * 100, 1),
        "avg_walk_in_ticket": avg_walkin_ticket,
        "avg_booked_ticket": avg_booked_ticket,
        "peak_walk_in_day": peak_walkin_day,
        "by_day": by_day,
        "monthly": monthly,
    }

