def _load_revenue_projection_stats():
    rng = _random200.Random(1407)
    months_past = ["Aug","Sep","Oct","Nov","Dec","Jan","Feb","Mar","Apr"]
    months_future = ["May","Jun","Jul","Aug"]
    actuals = []
    base = rng.uniform(14000, 18000)
    for m in months_past:
        base *= rng.uniform(0.97, 1.08)
        actuals.append({"month": m, "revenue": round(base, 2), "type": "actual"})
    projected = []
    proj_base = actuals[-1]["revenue"]
    for m in months_future:
        proj_base *= rng.uniform(1.02, 1.07)
        low = round(proj_base * rng.uniform(0.92, 0.97), 2)
        high = round(proj_base * rng.uniform(1.03, 1.08), 2)
        projected.append({"month": m, "projected": round(proj_base, 2), "low": low, "high": high, "type": "projected"})
    ytd_total = round(sum(a["revenue"] for a in actuals), 2)
    avg_monthly = round(ytd_total / len(actuals), 2)
    projected_annual = round(avg_monthly * 12 * rng.uniform(1.04, 1.10), 2)
    yoy_growth = round(rng.uniform(14, 28), 1)
    next_month_projection = projected[0]["projected"]
    return {
        "ytd_revenue": ytd_total,
        "avg_monthly_revenue": avg_monthly,
        "projected_annual_revenue": projected_annual,
        "yoy_growth_pct": yoy_growth,
        "next_month_projection": next_month_projection,
        "actuals": actuals,
        "projected": projected,
    }

@app.get("/api/analytics/revenue-projection-stats")
async def get_revenue_projection_stats():
    return _load_revenue_projection_stats()

