def _load_call_outcome_stats():
    rng = _random200.Random(1413)
    outcomes = [
        {"outcome": "Appointment Booked", "count": rng.randint(90, 180), "color": "#34d399"},
        {"outcome": "Info Provided, No Book", "count": rng.randint(15, 35), "color": "#a78bfa"},
        {"outcome": "Transferred to Staff", "count": rng.randint(12, 28), "color": "#fbbf24"},
        {"outcome": "Cancellation Processed", "count": rng.randint(8, 20), "color": "#f87171"},
        {"outcome": "Reschedule Processed", "count": rng.randint(10, 22), "color": "#fb923c"},
        {"outcome": "Abandoned / Hung Up", "count": rng.randint(5, 15), "color": "#666"},
    ]
    total = sum(o["count"] for o in outcomes)
    for o in outcomes:
        o["pct"] = round(o["count"] / total * 100, 1)
    months = ["Aug","Sep","Oct","Nov","Dec","Jan","Feb","Mar","Apr","May","Jun","Jul"]
    monthly = []
    for m in months:
        booked = rng.randint(60, 150)
        other = rng.randint(20, 60)
        monthly.append({
            "month": m,
            "booked": booked,
            "other": other,
            "total": booked + other,
            "booking_rate_pct": round(booked / (booked + other) * 100, 1),
        })
    top_outcome = max(outcomes, key=lambda x: x["count"])["outcome"]
    avg_booking_rate = round(sum(m["booking_rate_pct"] for m in monthly) / len(monthly), 1)
    return {
        "total_calls_30d": total,
        "top_outcome": top_outcome,
        "booking_rate_pct_30d": outcomes[0]["pct"],
        "avg_booking_rate_pct_12m": avg_booking_rate,
        "transfer_rate_pct": outcomes[2]["pct"],
        "outcomes": outcomes,
        "monthly": monthly,
    }

