@app.get("/api/analytics/peak-hour-stats")
async def get_peak_hour_stats():
    rng = _random206.Random(1523)
    hours = []
    for h in range(8, 20):
        label = f"{h}:00" if h < 12 else (f"12:00" if h == 12 else f"{h-12}:00 PM")
        label = f"{h}:00 AM" if h < 12 else (f"12:00 PM" if h == 12 else f"{h-12}:00 PM")
        calls = rng.randint(5, 85)
        booked = rng.randint(int(calls*0.5), calls)
        hours.append({"hour": h, "label": label, "calls": calls, "booked": booked})
    peak = max(hours, key=lambda x: x["calls"])
    slowest = min(hours, key=lambda x: x["calls"])
    months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"]
    monthly = [{"month": m, "peak_hour": rng.randint(10, 16), "total_calls": rng.randint(300, 700)} for m in months]
    return {
        "peak_hour_label": peak["label"],
        "peak_calls": peak["calls"],
        "slowest_hour_label": slowest["label"],
        "busiest_day": rng.choice(["Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"]),
        "avg_calls_per_hour": round(sum(h["calls"] for h in hours)/len(hours), 1),
        "hours": hours,
        "monthly": monthly,
    }

@app.get("/analytics/peak-hour-stats", response_class=HTMLResponse)
async def page_peak_hour_stats():
    with open("peak_hour_analytics.html") as f:
        return f.read()

