@app.get("/api/analytics/projected-revenue-stats")
async def get_projected_revenue_stats():
    rng = _random209.Random(1571)
    months_past = ["Oct","Nov","Dec","Jan","Feb","Mar"]
    months_future = ["Apr","May","Jun","Jul","Aug","Sep"]
    actuals = [{"month": m, "revenue": rng.randint(18000, 42000), "actual": True} for m in months_past]
    projections = [{"month": m, "revenue": rng.randint(22000, 48000), "actual": False,
                    "low": rng.randint(18000, 22000), "high": rng.randint(42000, 52000)} for m in months_future]
    all_months = actuals + projections
    current_month_rev = actuals[-1]["revenue"]
    projected_next = projections[0]["revenue"]
    return {
        "current_month_revenue": current_month_rev,
        "projected_next_month": projected_next,
        "projected_annual_run_rate": round(projected_next * 12),
        "mom_growth_pct": round((projected_next - current_month_rev) / current_month_rev * 100, 1),
        "avg_monthly_actual": round(sum(a["revenue"] for a in actuals) / len(actuals)),
        "months": all_months,
    }

