@app.get("/api/analytics/staff-avail-stats")
async def get_staff_avail_stats():
    rng = _random211.Random(1597)
    staff = [
        {"name": "Alex M.", "role": "Senior Stylist"},
        {"name": "Jordan K.", "role": "Colorist"},
        {"name": "Sam R.", "role": "Nail Tech"},
        {"name": "Casey L.", "role": "Esthetician"},
        {"name": "Morgan T.", "role": "Junior Stylist"},
    ]
    days = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
    result = []
    for s in staff:
        weekly = {}
        for d in days:
            weekly[d] = {
                "available": rng.random() > 0.15,
                "booked_slots": rng.randint(0, 8),
                "total_slots": 8,
            }
        utilization = round(sum(weekly[d]["booked_slots"] for d in days) / (len(days) * 8) * 100, 1)
        result.append({**s, "weekly": weekly, "avg_utilization_pct": utilization,
                       "next_available": rng.choice(["Today 3pm", "Tomorrow 10am", "Tomorrow 2pm", "Wed 11am"])})
    return {
        "total_staff": len(staff),
        "avg_utilization_pct": round(sum(s["avg_utilization_pct"] for s in result) / len(result), 1),
        "fully_booked_today": rng.randint(0, 2),
        "open_slots_today": rng.randint(8, 24),
        "staff": result,
    }

