@app.get("/api/analytics/booking-funnel-stats")
async def get_booking_funnel_stats():
    rng = _random212.Random(1607)
    total_calls = rng.randint(600, 1200)
    reached_ai = int(total_calls * rng.uniform(0.88, 0.98))
    intent_identified = int(reached_ai * rng.uniform(0.78, 0.92))
    availability_checked = int(intent_identified * rng.uniform(0.82, 0.95))
    booking_attempted = int(availability_checked * rng.uniform(0.75, 0.92))
    booking_confirmed = int(booking_attempted * rng.uniform(0.82, 0.96))
    stages = [
        {"stage": "Total Calls", "count": total_calls, "pct": 100.0},
        {"stage": "AI Engaged", "count": reached_ai, "pct": round(reached_ai/total_calls*100, 1)},
        {"stage": "Intent Identified", "count": intent_identified, "pct": round(intent_identified/total_calls*100, 1)},
        {"stage": "Availability Checked", "count": availability_checked, "pct": round(availability_checked/total_calls*100, 1)},
        {"stage": "Booking Attempted", "count": booking_attempted, "pct": round(booking_attempted/total_calls*100, 1)},
        {"stage": "Booking Confirmed", "count": booking_confirmed, "pct": round(booking_confirmed/total_calls*100, 1)},
    ]
    months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"]
    monthly = [{"month": m, "conversion_pct": round(rng.uniform(48, 78), 1)} for m in months]
    return {
        "overall_conversion_pct": stages[-1]["pct"],
        "biggest_drop_stage": "Availability Checked",
        "calls_lost_to_no_availability": rng.randint(40, 120),
        "avg_funnel_duration_sec": rng.randint(75, 180),
        "stages": stages,
        "monthly": monthly,
    }

@app.get("/analytics/booking-funnel-stats", response_class=HTMLResponse)
async def page_booking_funnel_stats():
    with open("booking_funnel_analytics.html") as f:
        return f.read()

