import random as _random219

@app.get("/api/analytics/sentiment-score-stats")
async def get_sentiment_score_stats():
    rng = _random219.Random(1667)
    labels = ["Very Positive", "Positive", "Neutral", "Negative", "Very Negative"]
    raw = [rng.randint(30, 120), rng.randint(80, 200), rng.randint(40, 100), rng.randint(10, 50), rng.randint(2, 20)]
    total = sum(raw)
    buckets = [{"label": l, "count": c, "pct": round(c / total * 100, 1)} for l, c in zip(labels, raw)]
    trend = [{"week": f"W{i+1}", "avg_score": round(rng.uniform(3.2, 4.8), 2)} for i in range(8)]
    return {
        "avg_sentiment_score": round(sum(b["pct"] * (5 - i) / 5 for i, b in enumerate(buckets)) / 100 * 5, 2),
        "positive_pct": round((raw[0] + raw[1]) / total * 100, 1),
        "negative_pct": round((raw[3] + raw[4]) / total * 100, 1),
        "total_scored_calls": total,
        "buckets": buckets,
        "trend": trend,
    }

