    for r in reasons: r["pct"] = round(r["count"] / rt * 100, 1)
    return {
        "missed_calls_30d": total_missed,
        "callback_rate_pct": round(callback_done / total_missed * 100, 1),
        "booked_from_callback": booked_from_callback,
        "recovery_rate_pct": round(booked_from_callback / total_missed * 100, 1),
        "hourly": hourly,
        "reasons": reasons,
    }

