import random as _random220

@app.get("/api/analytics/busy-hours-stats")
async def get_busy_hours_stats():
    rng = _random220.Random(1677)
    hours = []
    for h in range(8, 21):
        calls = rng.randint(5, 60)
        bookings = rng.randint(2, calls)
        hours.append({"hour": f"{h:02d}:00", "calls": calls, "bookings": bookings,
                       "utilisation_pct": round(rng.uniform(20, 95), 1)})
    peak = max(hours, key=lambda x: x["calls"])
    slowest = min(hours, key=lambda x: x["calls"])
    days = []
    for d in ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"]:
        days.append({"day": d, "calls": rng.randint(20, 180), "avg_wait_min": round(rng.uniform(0.5, 4.5), 1)})
    return {
        "peak_hour": peak["hour"],
        "peak_calls": peak["calls"],
        "slowest_hour": slowest["hour"],
        "avg_daily_calls": round(sum(d["calls"] for d in days) / len(days), 1),
        "hours": hours,
        "days": days,
    }

