import random as _random222

@app.get("/api/analytics/monthly-forecast-stats")
async def get_monthly_forecast_stats():
    rng = _random222.Random(1697)
    base = rng.randint(8000, 22000)
    months_actual = []
    for i in range(6):
        base = int(base * rng.uniform(0.95, 1.12))
        months_actual.append({"month": f"M-{5-i}", "revenue": base, "bookings": rng.randint(60, 300)})
    months_actual.reverse()
    growth_rate = rng.uniform(0.04, 0.12)
    last = months_actual[-1]["revenue"]
    forecast = []
    for i in range(3):
        projected = int(last * ((1 + growth_rate) ** (i + 1)))
        forecast.append({"month": f"M+{i+1}", "projected": projected,
                          "low": int(projected * 0.88), "high": int(projected * 1.14)})
    return {
        "current_month_revenue": months_actual[-1]["revenue"],
        "prev_month_revenue": months_actual[-2]["revenue"],
        "mom_growth_pct": round((months_actual[-1]["revenue"] / months_actual[-2]["revenue"] - 1) * 100, 1),
        "projected_next_month": forecast[0]["projected"],
        "monthly_growth_rate_pct": round(growth_rate * 100, 1),
        "actuals": months_actual,
        "forecast": forecast,
    }

