import random as _random225

@app.get("/api/analytics/voicemail-stats")
async def get_voicemail_stats():
    rng = _random225.Random(1727)
    total = rng.randint(30, 120)
    transcribed = rng.randint(int(total * 0.80), total)
    actioned = rng.randint(int(transcribed * 0.50), transcribed)
    daily = [{"day": f"D-{6-i}", "count": rng.randint(0, 18)} for i in range(7)]
    reasons = [
        {"reason": "After hours", "count": rng.randint(10, 50), "pct": 0},
        {"reason": "All lines busy", "count": rng.randint(5, 25), "pct": 0},
        {"reason": "Client chose voicemail", "count": rng.randint(3, 15), "pct": 0},
        {"reason": "Transfer no answer", "count": rng.randint(2, 10), "pct": 0},
    ]
    rt = sum(r["count"] for r in reasons)
    for r in reasons:
        r["pct"] = round(r["count"] / rt * 100, 1)
    return {
        "voicemails_30d": total,
        "transcribed_pct": round(transcribed / total * 100, 1),
        "actioned_pct": round(actioned / total * 100, 1),
        "avg_duration_sec": rng.randint(20, 90),
        "daily": daily,
        "reasons": reasons,
    }

