_HSC_SEED = 1861
@app.get("/api/analytics/hourly-staff-cost-stats")
async def get_hourly_staff_cost_stats():
    rng = _random238.Random(_HSC_SEED)
    hours = []
    for h in range(8, 21):
        label = f"{h:02d}:00"
        cost = round(rng.uniform(12, 28), 2)
        revenue = round(rng.uniform(30, 120) if 10 <= h <= 18 else rng.uniform(5, 45), 2)
        hours.append({"hour": h, "label": label, "staff_cost": cost, "revenue": revenue, "margin": round(revenue - cost, 2)})
    total_cost = round(sum(x["staff_cost"] for x in hours), 2)
    total_rev = round(sum(x["revenue"] for x in hours), 2)
    return {
        "total_daily_staff_cost": total_cost,
        "total_daily_revenue": total_rev,
        "overall_margin": round(total_rev - total_cost, 2),
        "margin_pct": round((total_rev - total_cost) / total_rev * 100, 1),
        "peak_margin_hour": max(hours, key=lambda x: x["margin"])["label"],
        "hours": hours,
    }

