    transferred = rng.randint(int(total * .04), int(total * .10))
    voicemail = rng.randint(int(total * .03), int(total * .08))
    other = total - booked - info - transferred - voicemail
    dispositions = [
        {"label": "Booking made", "count": booked, "pct": round(booked/total*100,1), "color": "green"},
        {"label": "Info only", "count": info, "pct": round(info/total*100,1), "color": "accent"},
        {"label": "Transferred", "count": transferred, "pct": round(transferred/total*100,1), "color": "yellow"},
        {"label": "Voicemail", "count": voicemail, "pct": round(voicemail/total*100,1), "color": "muted"},
        {"label": "Other", "count": max(other,0), "pct": round(max(other,0)/total*100,1), "color": "muted"},
    ]
    return {"total_calls_30d": total, "dispositions": dispositions, "booking_rate_pct": round(booked/total*100,1)}

