    services = ["Haircut","Colour","Highlights","Blowdry","Treatment","Beard Trim"]
    result = []
    for svc in services:
        avg_gap = round(rng.uniform(14, 56), 1)
        bookings = rng.randint(10, 60)
        result.append({"service": svc, "avg_gap_days": avg_gap, "bookings_30d": bookings, "overdue_pct": round(rng.uniform(10, 40), 1)})
    result.sort(key=lambda x: x["avg_gap_days"])
    return {"services": result, "overall_avg_gap_days": round(sum(s["avg_gap_days"] for s in result) / len(result), 1)}

