        rng = _random294.Random(2421)
        types = [
            {"type": "Appointment Reminder", "sent": rng.randint(180, 320), "responded": 0, "response_rate": 0},
            {"type": "Booking Confirmation",  "sent": rng.randint(120, 240), "responded": 0, "response_rate": 0},
            {"type": "Cancellation Notice",   "sent": rng.randint(30, 80),  "responded": 0, "response_rate": 0},
            {"type": "Promotional Offer",     "sent": rng.randint(80, 180), "responded": 0, "response_rate": 0},
        ]
        for t in types:
            t["responded"] = rng.randint(int(t["sent"] * 0.18), int(t["sent"] * 0.52))
