            {"month": "Jun", "bookings": rng.randint(230, 360), "revenue": 0},
            {"month": "Jul", "bookings": rng.randint(220, 350), "revenue": 0},
            {"month": "Aug", "bookings": rng.randint(210, 340), "revenue": 0},
            {"month": "Sep", "bookings": rng.randint(200, 320), "revenue": 0},
            {"month": "Oct", "bookings": rng.randint(190, 300), "revenue": 0},
