    try:
        with open(_CLIENT_ACQ_COST_FILE) as f: return json.load(f)
    except FileNotFoundError:
        rng = _random309.Random(2569)
        channels = [
            {"channel": "Google Ads",    "spend": round(rng.uniform(200, 600), 2), "new_clients": rng.randint(8, 28)},
            {"channel": "Instagram",     "spend": round(rng.uniform(80,  250), 2), "new_clients": rng.randint(5, 18)},
            {"channel": "Referral",      "spend": round(rng.uniform(30,  90),  2), "new_clients": rng.randint(10, 30)},
            {"channel": "Walk-in",       "spend": 0.0,                             "new_clients": rng.randint(6, 20)},
        ]
        for c in channels:
            c["cac"] = round(c["spend"] / c["new_clients"], 2) if c["new_clients"] > 0 and c["spend"] > 0 else 0.0
        total_spend = sum(c["spend"] for c in channels)
        total_clients = sum(c["new_clients"] for c in channels)
        return {"total_new_clients_30d": total_clients, "total_acq_spend_30d": round(total_spend, 2), "blended_cac": round(total_spend / total_clients, 2) if total_clients else 0.0, "best_channel": min((c for c in channels if c["cac"] > 0), key=lambda c: c["cac"])["channel"], "channels": channels}

