@app.get("/api/analytics/booking-source-conversion-stats")
async def get_booking_source_conversion_stats():
    try:
        with open(_BOOKING_SRC_CONV_FILE) as f: return json.load(f)
    except FileNotFoundError:
        rng = _random311.Random(2591)
        sources = [
            {"source": "AI Phone Call",   "leads": rng.randint(120, 280), "bookings": 0, "conv_pct": 0.0},
            {"source": "Online Widget",   "leads": rng.randint(80,  180), "bookings": 0, "conv_pct": 0.0},
            {"source": "SMS Campaign",    "leads": rng.randint(30,   80), "bookings": 0, "conv_pct": 0.0},
            {"source": "Google Business", "leads": rng.randint(40,  100), "bookings": 0, "conv_pct": 0.0},
            {"source": "Instagram Link",  "leads": rng.randint(20,   60), "bookings": 0, "conv_pct": 0.0},
        ]
        conv_rates = [round(rng.uniform(0.55, 0.82), 2) for _ in sources]
        for s, r in zip(sources, conv_rates):
            s["bookings"] = int(s["leads"] * r)
            s["conv_pct"] = round(r * 100, 1)
        best = max(sources, key=lambda s: s["conv_pct"])
        total_bookings = sum(s["bookings"] for s in sources)
        return {"total_bookings_30d": total_bookings, "best_converting_source": best["source"], "best_conv_pct": best["conv_pct"], "sources": sources}

